INSERT INTO `ai_chat_log` VALUES (1, 7, '显微镜怎么调焦距？', '您好！光学显微镜调焦步骤如下：\n\n1. 先用低倍镜（4x或10x）观察，将标本移到视野中央\n2. 慢慢转动粗调旋钮，直到标本图像出现\n3. 再用细调旋钮微调至最清晰\n4. 如需更换高倍镜，只需轻轻转动物镜转换器，选择高倍镜，再用细调旋钮微调即可\n\n注意事项：\n- 使用高倍镜时不要用粗调旋钮调焦\n- 调焦时要从标本下方慢慢向上调', 1, 1, 0.95, 156, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (2, 7, '离心机不平衡怎么办？', '离心机不平衡会导致震动和报警，请按以下步骤处理：\n\n1. 立即按下停止键，等待离心机完全停止\n2. 打开机盖，检查样品管\n3. 确保所有样品管对称放置\n4. 检查样品管重量是否相等（误差<0.1g）\n5. 如有单个样品管，使用配重管平衡\n6. 重新放置样品后再次离心\n\n注意：如离心机有异常震动或噪音，请联系维修人员检查。', 2, 8, 0.92, 203, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (3, 8, '天平怎么校准？', '分析天平校准步骤：\n\n1. 确保天平已预热30分钟\n2. 检查天平是否水平（观察水平仪气泡）\n3. 按\"CAL\"键进入校准模式\n4. 等待显示\"0.0\"后放置校准砝码\n5. 等待校准完成，显示\"PASS\"\n6. 取下砝码，校准完成\n\n建议：\n- 每月校准一次\n- 更换位置后需重新校准\n- 环境温度变化超过5°C需重新校准', 3, 15, 0.88, 189, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (4, 10, '分光光度计怎么测样品浓度？', '使用分光光度计测定样品浓度步骤：\n\n1. 开机预热30分钟\n2. 设置测定波长（根据样品特性选择）\n3. 用空白溶液（溶剂）调零\n4. 放入样品溶液（比色皿光学面朝光路）\n5. 读取吸光度（A）值\n6. 如有标准曲线，根据A值计算浓度\n7. 如测定系列浓度，制作标准曲线后计算\n\n注意事项：\n- 样品溶液要清澈无浑浊\n- 比色皿用完要洗净擦干', 4, 18, 0.91, 234, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (5, 8, 'PCR反应程序怎么设置？', '标准PCR反应程序设置（以25μL体系为例）：\n\n1. 预变性：94-95°C，2-5分钟\n2. 循环（25-35次）：\n   - 变性：94-95°C，30秒\n   - 退火：50-65°C，30秒（温度根据引物设计）\n   - 延伸：72°C，30秒-1分钟（根据片段长度）\n3. 最后延伸：72°C，5-10分钟\n4. 保存：4°C，∞\n\n注意：退火温度需要根据引物的Tm值计算。', 6, 24, 0.89, 267, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (6, 11, '显微镜视野模糊怎么办？', '显微镜视野模糊常见原因及解决方法：\n\n1. 物镜未对准\n   → 旋转物镜至咔哒声响起\n\n2. 标本上有气泡或杂质\n   → 重新制作标本\n\n3. 镜头脏污\n   → 用拭镜纸轻轻擦拭镜头\n\n4. 未使用油镜但使用了香柏油\n   → 用酒精乙醚混合液清洁\n\n5. 载玻片放反\n   → 确保标本面朝下\n\n如果以上都不能解决，可能是光路问题，请联系维修人员。', 11, 1, 0.94, 178, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (7, 9, 'CO2培养箱怎么消毒？', 'CO2培养箱消毒步骤：\n\n1. 取出所有培养物\n2. 用70%酒精擦拭内壁\n3. 打开紫外灯照射30分钟\n4. 如需高温灭菌，设置90°C运行2小时\n5. 通风换气后即可使用\n\n注意事项：\n- 每周至少消毒一次\n- 频繁消毒会影响传感器精度\n- 日常使用用酒精擦拭即可\n- 每月进行彻底清洁', 5, 21, 0.9, 212, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (8, 12, '高压灭菌锅怎么使用？', '高压灭菌锅使用步骤：\n\n1. 添加适量水（至少覆盖加热盘）\n2. 放入待灭菌物品\n3. 盖紧锅盖，检查密封圈\n4. 设定灭菌参数：\n   - 液体模式：121°C，20分钟\n   - 器械模式：134°C，10分钟\n5. 启动灭菌程序\n6. 等待压力降为0\n7. 佩戴手套打开盖子\n\n安全提醒：\n- 液体灭菌时容器盖子要松\n- 禁止带压开盖\n- 定期检查安全阀', 9, 27, 0.93, 198, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (9, 7, '我想预约显微镜做实验', '您好！预约显微镜的步骤如下：\n\n1. 进入设备列表页面\n2. 选择需要的显微镜设备\n3. 点击\"预约\"按钮\n4. 填写预约信息：\n   - 预约日期和时间\n   - 实验项目名称\n   - 参与人数\n   - 预约事由\n5. 提交申请\n6. 等待管理员审核\n\n注意事项：\n- 学生预约需提前24小时\n- 电子显微镜需专业培训后才能预约使用\n- 单次预约最长4小时', NULL, NULL, 0.85, 145, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (10, 10, '天平显示err怎么回事？', '天平显示\"Err\"可能有以下原因：\n\n1. 超载 - 称量的物品超过天平最大量程，请减少样品量\n2. 称量盘未放置 - 确保称量盘正确放置\n3. 环境不稳定 - 移动到稳定环境后重新操作\n4. 传感器故障 - 长按开关机重启天平\n\n解决方法：\n1. 先移除样品，看是否恢复正常\n2. 关闭天平，等待30秒后重新开机\n3. 如问题持续，请联系维修人员报修', 13, 15, 0.87, 167, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (11, 7, '???????', '抱歉，我无法理解您的问题。请尝试以下方式：\n1. 使用更简洁的关键词描述（如：设备名称+操作类型）\n2. 查看设备操作手册\n3. 联系实验室管理员\n4. 拨打设备维护热线', NULL, NULL, 0, 524, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (12, 24, '离心机如何操作？', '离心机标准操作流程：\n1. 检查离心管是否平衡，对称放置\n2. 设置转速和时间参数\n3. 关闭机盖，确保安全锁扣到位\n4. 启动离心机，等待达到设定转速\n5. 离心结束后，等待转子完全停止再开盖\n6. 小心取出样品，避免离心管破碎\n注意事项：严禁在运行时打开机盖，转子需定期保养', 18, 5, 2.75, 361, '2026-04-11 19:53:54');
