INSERT INTO `ai_chat_log` VALUES (16, 24, '高压设备有什么危险？', '⚠️ 安全警告：高压容器安全使用规范：\n1. 定期检验压力容器\n2. 禁止碰撞和敲击\n3. 远离热源和易燃物\n4. 使用专用减压阀\n5. 检查管路连接是否漏气\n6. 带压时禁止拆卸\n7. 气瓶要固定放置\n注意：高压灭菌锅、高压气瓶等', 39, NULL, 1.7400000000000002, 25, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (17, 24, '有毒化学品如何处理？', '⚠️ 安全警告：化学品溢洒处理步骤：\n1. 立即疏散人员\n2. 穿戴防护装备\n3. 围堵溢洒区域\n4. 用适当吸收材料覆盖\n5. 小心收集废液\n6. 用清水冲洗地面\n7. 废液倒入废液桶\n注意：不要直接用手接触', 41, NULL, 2.124, 29, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (18, 24, '设备故障如何报修？', '设备故障报修步骤：\n1. 登录系统\n2. 进入维修管理页面\n3. 点击报修按钮\n4. 选择故障设备\n5. 详细描述故障现象\n6. 可上传故障图片\n7. 提交报修申请\n8. 等待维修人员处理', 16, NULL, 2.85, 21, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (19, 24, '遇到智能冲突检测冲突怎么办？', '预约冲突解决方法：\n1. 系统会自动检测时间冲突\n2. 如有冲突可选择其他时间\n3. 可查看推荐的可替代设备\n4. 如需帮助联系管理员\n5. 避免同一时段重复预约\n建议提前规划实验时间', 59, NULL, 1.5833333333333333, 27, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (20, 24, 'cscs', '抱歉，我无法理解您的问题。请尝试以下方式：\n1. 使用更简洁的关键词描述（如：设备名称+操作类型）\n2. 查看设备操作手册\n3. 联系实验室管理员\n4. 拨打设备维护热线', NULL, NULL, 0, 17, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (21, 1, '光谱仪如何校准', '电子天平校准流程：\n1. 确保天平放置在平稳、无振动的台面\n2. 预热30分钟以上\n3. 按下CAL键进入校准模式\n4. 放置标准砝码或使用内置砝码\n5. 等待校准完成，显示零点\n6. 校准后可进行称量操作\n注意事项：称量时避免震动和气流影响', 21, 15, 1.53, 414, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (22, 1, '显微镜如何操作？', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 2.4000000000000004, 26, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (23, 1, '离心机如何操作？', '离心机标准操作流程：\n1. 检查离心管是否平衡，对称放置\n2. 设置转速和时间参数\n3. 关闭机盖，确保安全锁扣到位\n4. 启动离心机，等待达到设定转速\n5. 离心结束后，等待转子完全停止再开盖\n6. 小心取出样品，避免离心管破碎\n注意事项：严禁在运行时打开机盖，转子需定期保养', 18, 5, 2.75, 92, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (24, 1, '如何预约设备？', '设备预约步骤：\n1. 登录系统\n2. 进入设备列表页面\n3. 选择需要预约的设备\n4. 点击预约按钮\n5. 填写预约信息（日期、时间、实验项目等）\n6. 提交预约申请\n7. 等待审核', 7, NULL, 2.81, 21, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (25, 1, '设备故障如何报修？', '设备故障报修步骤：\n1. 登录系统\n2. 进入维修管理页面\n3. 点击报修按钮\n4. 选择故障设备\n5. 详细描述故障现象\n6. 可上传故障图片\n7. 提交报修申请\n8. 等待维修人员处理', 16, NULL, 2.85, 22, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (26, 1, '设备故障如何报修？', '设备故障报修步骤：\n1. 登录系统\n2. 进入维修管理页面\n3. 点击报修按钮\n4. 选择故障设备\n5. 详细描述故障现象\n6. 可上传故障图片\n7. 提交报修申请\n8. 等待维修人员处理', 16, NULL, 2.85, 34, '2026-04-11 19:53:54');
