INSERT INTO `ai_chat_log` VALUES (28, 1, '火灾', '⚠️ 警告：实验室火灾应急处理：\n1. 立即切断电源和气源\n2. 小火用灭火器扑灭\n3. 火势大立即疏散\n4. 拨打119报警\n5. 从安全通道撤离\n6. 实验室着火禁用消防水\n7. 定期检查消防器材\n常用灭火器：CO2、干粉灭火器', 40, NULL, 1.35, 23, '2026-04-11 19:53:54');
