INSERT INTO `ai_chat_log` VALUES (31, 1, '光', '分光光度计操作步骤：\n1. 打开仪器电源，预热30分钟\n2. 设置测量波长\n3. 用空白溶液调零\n4. 放入样品溶液\n5. 读取吸光度或透光率\n6. 测量完毕后清洗比色皿', 4, 18, 1.1, 23, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (32, 1, '有毒化学品如何处理？', '⚠️ 安全警告：化学品溢洒处理步骤：\n1. 立即疏散人员\n2. 穿戴防护装备\n3. 围堵溢洒区域\n4. 用适当吸收材料覆盖\n5. 小心收集废液\n6. 用清水冲洗地面\n7. 废液倒入废液桶\n注意：不要直接用手接触', 41, NULL, 2.124, 24, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (33, 1, '火', '⚠️ 警告：实验室火灾应急处理：\n1. 立即切断电源和气源\n2. 小火用灭火器扑灭\n3. 火势大立即疏散\n4. 拨打119报警\n5. 从安全通道撤离\n6. 实验室着火禁用消防水\n7. 定期检查消防器材\n常用灭火器：CO2、干粉灭火器', 40, NULL, 0.85, 18, '2026-04-11 19:53:54');
