INSERT INTO `ai_chat_log` VALUES (35, 1, '光谱图', '光谱分析基本流程：\n1. 样品前处理\n2. 选择测定波长\n3. 仪器校准和基线校正\n4. 制作标准曲线\n5. 测定样品\n6. 数据处理和计算\n注意：样品需清澈无颗粒', 35, NULL, 1.33, 19, '2026-04-11 19:53:54');
