INSERT INTO `ai_chat_log` VALUES (38, 24, '查看设备操作手册', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 1.5, 28, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (39, 24, '联系实验室管理员', '联系管理员方式：\n1. 系统消息功能发送咨询\n2. 拨打管理员办公电话\n3. 前往实验室管理办公室\n4. 邮件联系实验室邮箱\n5. 工作时间：周一至周五 8:00-17:00\n紧急情况可电话联系', 65, NULL, 2.4000000000000004, 56, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (40, 24, '拨打设备维护热线', '设备预约流程：\n1. 登录系统，进入设备预约模块\n2. 选择需要的设备类型\n3. 查看设备可用时间\n4. 填写预约信息：使用时间、实验项目、参与人数等\n5. 提交预约申请\n6. 等待管理员审核\n7. 审核通过后按时使用设备', 57, NULL, 1.5, 24, '2026-04-11 19:53:54');
