INSERT INTO `ai_chat_log` VALUES (43, 1, '·', '设备预约步骤：\n1. 登录系统\n2. 进入设备列表页面\n3. 选择需要预约的设备\n4. 点击预约按钮\n5. 填写预约信息（日期、时间、实验项目等）\n6. 提交预约申请\n7. 等待审核', 7, NULL, 0.5, 203, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (44, 1, '显微镜的基本操作步骤是什么？', '设备预约步骤：\n1. 登录系统\n2. 进入设备列表页面\n3. 选择需要预约的设备\n4. 点击预约按钮\n5. 填写预约信息（日期、时间、实验项目等）\n6. 提交预约申请\n7. 等待审核', 7, NULL, 1.83, 27, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (45, 1, '显微镜怎么使用？', '光学显微镜操作步骤：\n1. 打开显微镜电源，调至最低倍镜\n2. 将待观察标本放置于载物台上\n3. 使用粗调旋钮下降载物台至标本接近物镜\n4. 从目镜观察，同时缓慢上升载物台直至图像清晰\n5. 切换至高倍镜时只需微调细调旋钮\n6. 观察结束后先将载物台降至最低，关闭电源\n注意事项：不可用手直接擦拭镜头，使用专用镜头纸', 17, 1, 1.6500000000000001, 19, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (46, 1, '显微镜操作方法', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 1.75, 26, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (47, 1, '显微镜如何开机', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 1.6500000000000001, 25, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (48, 1, '光谱仪校准步骤', '电子天平校准流程：\n1. 确保天平放置在平稳、无振动的台面\n2. 预热30分钟以上\n3. 按下CAL键进入校准模式\n4. 放置标准砝码或使用内置砝码\n5. 等待校准完成，显示零点\n6. 校准后可进行称量操作\n注意事项：称量时避免震动和气流影响', 21, 15, 1.4300000000000002, 25, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (49, 1, '光谱仪校准步骤', '电子天平校准流程：\n1. 确保天平放置在平稳、无振动的台面\n2. 预热30分钟以上\n3. 按下CAL键进入校准模式\n4. 放置标准砝码或使用内置砝码\n5. 等待校准完成，显示零点\n6. 校准后可进行称量操作\n注意事项：称量时避免震动和气流影响', 21, 15, 1.4300000000000002, 21, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (50, 1, '光谱仪', '分光光度计操作步骤：\n1. 打开仪器电源，预热30分钟\n2. 设置测量波长\n3. 用空白溶液调零\n4. 放入样品溶液\n5. 读取吸光度或透光率\n6. 测量完毕后清洗比色皿', 4, 18, 1.35, 16, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (51, 1, '设备故障怎么办', '设备故障报修步骤：\n1. 登录系统\n2. 进入维修管理页面\n3. 点击报修按钮\n4. 选择故障设备\n5. 详细描述故障现象\n6. 可上传故障图片\n7. 提交报修申请\n8. 等待维修人员处理', 16, NULL, 1.6833333333333333, 48, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (52, 1, '离心机怎么操作？', '高速离心机操作步骤：\n1. 检查离心机是否平稳放置\n2. 打开机盖，将样品对称放置在转子中\n3. 确保样品管已盖紧且重量相等\n4. 关闭机盖，确保锁紧\n5. 设置转速和时间\n6. 按启动键开始离心\n7. 离心完成后等待完全停止再打开机盖', 2, 8, 2.25, 22, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (53, 1, '设备着火怎么办？', '设备故障处理流程：\n1. 立即停止使用设备\n2. 记录故障现象和发生时间\n3. 在系统中提交故障报修\n4. 保护现场，不擅自拆卸\n5. 等待维修人员处理\n6. 如影响实验可申请设备替换\n紧急情况请联系管理员', 61, NULL, 1.5214285714285716, 21, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (54, 1, '高压设备有什么危险？', '⚠️ 安全警告：高压容器安全使用规范：\n1. 定期检验压力容器\n2. 禁止碰撞和敲击\n3. 远离热源和易燃物\n4. 使用专用减压阀\n5. 检查管路连接是否漏气\n6. 带压时禁止拆卸\n7. 气瓶要固定放置\n注意：高压灭菌锅、高压气瓶等', 39, NULL, 1.7400000000000002, 22, '2026-04-11 19:53:54');
