INSERT INTO `ai_chat_log` VALUES (56, 1, '有毒化学品如何处理？', '⚠️ 安全警告：化学品溢洒处理步骤：\n1. 立即疏散人员\n2. 穿戴防护装备\n3. 围堵溢洒区域\n4. 用适当吸收材料覆盖\n5. 小心收集废液\n6. 用清水冲洗地面\n7. 废液倒入废液桶\n注意：不要直接用手接触', 41, NULL, 2.124, 23, '2026-04-11 19:53:54');
