INSERT INTO `ai_chat_log` VALUES (59, 1, '高温设备烫伤了', '设备预约流程：\n1. 登录系统，进入设备预约模块\n2. 选择需要的设备类型\n3. 查看设备可用时间\n4. 填写预约信息：使用时间、实验项目、参与人数等\n5. 提交预约申请\n6. 等待管理员审核\n7. 审核通过后按时使用设备', 57, NULL, 1.5, 22, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (60, 1, '高温设备表面温度极高，触碰可能造成烫伤。请佩戴隔热手套。', '干燥箱使用规范：\n1. 打开电源开关，设定目标温度\n2. 温度设置范围根据样品确定（一般不超过300℃）\n3. 等待温度升至设定值\n4. 放入样品，关闭箱门\n5. 定时检查温度变化\n6. 干燥完成后取出样品，关闭电源\n注意事项：易燃物品禁止放入，保持箱内清洁', 20, 12, 1.3333333333333335, 37, '2026-04-11 19:53:54');
