INSERT INTO `ai_chat_log` VALUES (68, 1, '注意安全', '⚠️ 警告：重要安全提醒：\n1. 样品必须对称放置\n2. 离心管必须盖紧，防止样品泄漏\n3. 切勿在离心机运行时打开机盖\n4. 如有异常震动或噪音，立即停止并报修', 8, NULL, 1.884, 19, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (69, 1, '离心机如何操作？', '离心机标准操作流程：\n1. 检查离心管是否平衡，对称放置\n2. 设置转速和时间参数\n3. 关闭机盖，确保安全锁扣到位\n4. 启动离心机，等待达到设定转速\n5. 离心结束后，等待转子完全停止再开盖\n6. 小心取出样品，避免离心管破碎\n注意事项：严禁在运行时打开机盖，转子需定期保养', 18, 5, 2.75, 22, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (70, 4, '如何取消预约？', '取消预约步骤：\n1. 登录系统\n2. 进入我的预约页面\n3. 找到需要取消的预约记录\n4. 点击取消按钮\n5. 选择取消原因\n6. 确认取消\n\n注意：请至少提前2小时取消，以便其他用户预约。', 14, NULL, 2.85, 272, '2026-04-11 19:53:54');
