INSERT INTO `ai_chat_log` VALUES (73, 2, '光谱仪如何校准', '电子天平校准流程：\n1. 确保天平放置在平稳、无振动的台面\n2. 预热30分钟以上\n3. 按下CAL键进入校准模式\n4. 放置标准砝码或使用内置砝码\n5. 等待校准完成，显示零点\n6. 校准后可进行称量操作\n注意事项：称量时避免震动和气流影响', 21, 15, 1.53, 31, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (74, 2, '光谱仪', '分光光度计操作步骤：\n1. 打开仪器电源，预热30分钟\n2. 设置测量波长\n3. 用空白溶液调零\n4. 放入样品溶液\n5. 读取吸光度或透光率\n6. 测量完毕后清洗比色皿', 4, 18, 1.35, 17, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (75, 2, '显微镜如何操作？', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 2.4000000000000004, 21, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (76, 2, '这个步骤需要注意什么？', '⚠️ 警告：重要安全提醒：\n1. 样品必须对称放置\n2. 离心管必须盖紧，防止样品泄漏\n3. 切勿在离心机运行时打开机盖\n4. 如有异常震动或噪音，立即停止并报修', 8, NULL, 1.428, 20, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (77, 2, '设备无法开机怎么办？', '设备故障处理流程：\n1. 立即停止使用设备\n2. 记录故障现象和发生时间\n3. 在系统中提交故障报修\n4. 保护现场，不擅自拆卸\n5. 等待维修人员处理\n6. 如影响实验可申请设备替换\n紧急情况请联系管理员', 61, NULL, 1.5214285714285716, 20, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (78, 2, '我想用高压气体检查漏气', '⚠️ 安全警告：高压容器安全使用规范：\n1. 定期检验压力容器\n2. 禁止碰撞和敲击\n3. 远离热源和易燃物\n4. 使用专用减压阀\n5. 检查管路连接是否漏气\n6. 带压时禁止拆卸\n7. 气瓶要固定放置\n注意：高压灭菌锅、高压气瓶等', 39, NULL, 1.7160000000000002, 25, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (79, 2, '教我操作HPLC', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 1.5, 18, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (80, 2, '我想用有机溶剂直接接触皮肤', '⚠️ 警告：化学品皮肤接触处理：\n1. 立即脱去被污染衣物\n2. 用大量流动清水冲洗\n3. 冲洗时间15分钟以上\n4. 视情况使用适当中和剂\n5. 严重者立即就医\n6. 记录接触化学品信息\n注意：不要用力擦洗皮肤', 43, NULL, 1.5833333333333333, 21, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (81, 2, '不戴护目镜操作离心机', '高速离心机操作步骤：\n1. 检查离心机是否平稳放置\n2. 打开机盖，将样品对称放置在转子中\n3. 确保样品管已盖紧且重量相等\n4. 关闭机盖，确保锁紧\n5. 设置转速和时间\n6. 按启动键开始离心\n7. 离心完成后等待完全停止再打开机盖', 2, 8, 1.75, 20, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (82, 2, 'cs', '抱歉，我无法理解您的问题。请尝试以下方式：\n1. 使用更简洁的关键词描述（如：设备名称+操作类型）\n2. 查看设备操作手册\n3. 联系实验室管理员\n4. 拨打设备维护热线', NULL, NULL, 0, 273, '2026-04-11 19:53:54');
