INSERT INTO `ai_chat_log` VALUES (93, 2, '设备故障如何报修？', '设备故障报修步骤：\n1. 登录系统\n2. 进入维修管理页面\n3. 点击报修按钮\n4. 选择故障设备\n5. 详细描述故障现象\n6. 可上传故障图片\n7. 提交报修申请\n8. 等待维修人员处理', 16, NULL, 2.85, 545, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (94, 2, '显微镜如何操作？', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 2.4000000000000004, 61, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (95, 2, '如何预约设备？', '设备预约步骤：\n1. 登录系统\n2. 进入设备列表页面\n3. 选择需要预约的设备\n4. 点击预约按钮\n5. 填写预约信息（日期、时间、实验项目等）\n6. 提交预约申请\n7. 等待审核', 7, NULL, 2.81, 35, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (96, 2, '如何取消预约？', '取消预约步骤：\n1. 登录系统\n2. 进入我的预约页面\n3. 找到需要取消的预约记录\n4. 点击取消按钮\n5. 选择取消原因\n6. 确认取消\n\n注意：请至少提前2小时取消，以便其他用户预约。', 14, NULL, 2.85, 29, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (97, 2, '显微镜的基本操作步骤是什么？测试', ' <见下方>，测试，测试用例 2.3：编辑知识条目', 69, NULL, 3.216666666666667, 36, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (98, 2, '显微镜看不清怎么办？', '显微镜常见问题及解决方案：\n1. 物镜未对准 - 解决方法：旋转物镜至正确位置\n2. 标本放置不正确 - 重新放置标本\n3. 镜头脏污 - 用拭镜纸轻轻清洁镜头\n4. 照明不当 - 调整光源亮度\n如无法解决，请联系维护人员报修。', 11, 1, 3.35, 32, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (99, 2, '火', '⚠️ 警告：实验室火灾应急处理：\n1. 立即切断电源和气源\n2. 小火用灭火器扑灭\n3. 火势大立即疏散\n4. 拨打119报警\n5. 从安全通道撤离\n6. 实验室着火禁用消防水\n7. 定期检查消防器材\n常用灭火器：CO2、干粉灭火器', 40, NULL, 0.85, 28, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (100, 2, '光谱仪', '分光光度计操作步骤：\n1. 打开仪器电源，预热30分钟\n2. 设置测量波长\n3. 用空白溶液调零\n4. 放入样品溶液\n5. 读取吸光度或透光率\n6. 测量完毕后清洗比色皿', 4, 18, 1.35, 28, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (101, 1, '显微镜如何操作？', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 2.4000000000000004, 31, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (102, 1, '蛋白质纯化的标准流程是什么？', '蛋白质纯化基本流程：\n1. 样品准备：细胞破碎、离心取上清\n2. 盐析初步分离\n3. 离子交换层析\n4. 凝胶过滤层析\n5. 亲和层析（如需要）\n6. 透析除盐并浓缩\n7. SDS-PAGE电泳检测纯度\n每步操作后需测定蛋白浓度和活性', 27, NULL, 3.31, 26, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (103, 1, '如何预约设备？', '设备预约步骤：\n1. 登录系统\n2. 进入设备列表页面\n3. 选择需要预约的设备\n4. 点击预约按钮\n5. 填写预约信息（日期、时间、实验项目等）\n6. 提交预约申请\n7. 等待审核', 7, NULL, 3.31, 27, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (104, 1, 'PCR实验的标准流程是什么？', 'PCR实验标准流程：\n1. 试剂配制：模板DNA、引物、酶、dNTP\n2. 反应体系配制：总体积25-50μL\n3. 设置PCR程序\n4. 运行PCR反应\n5. 琼脂糖凝胶电泳检测结果\n6. 结果分析\n注意事项：设置阴性对照和阳性对照', 29, NULL, 1.9, 30, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (105, 1, '光谱分析的流程是什么？', '光谱分析基本流程：\n1. 样品前处理\n2. 选择测定波长\n3. 仪器校准和基线校正\n4. 制作标准曲线\n5. 测定样品\n6. 数据处理和计算\n注意：样品需清澈无颗粒', 35, NULL, 2.7500000000000004, 32, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (106, 1, '凝胶电泳的实验流程？', '凝胶电泳实验流程：\n1. 配制凝胶（琼脂糖或聚丙烯酰胺）\n2. 灌胶并插好梳子\n3. 凝胶凝固后拔梳子\n4. 点样：加入DNA marker和样品\n5. 电泳：设置电压和时间\n6. 染色：EB或GelRed染色\n7. 凝胶成像观察结果\n注意：琼脂糖凝胶不要超过5%', 34, NULL, 3.31, 26, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (107, 1, 'DNA提取的标准步骤？', 'DNA提取标准流程：\n1. 细胞或组织破碎\n2. 加入裂解液裂解细胞\n3. 蛋白质去除（酚/氯仿法或蛋白酶K）\n4. 乙醇或异丙醇沉淀DNA\n5. 70%乙醇洗涤\n6. 晾干后溶解于TE缓冲液\n7. 检测DNA浓度和纯度\n操作时避免剧烈震荡', 33, NULL, 3.23, 23, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (108, 1, '遇到智能冲突检测冲突怎么办？', '水质检测标准流程：\n1. 采样：使用专用采样瓶采集水样\n2. 样品保存：根据检测项目添加保存剂\n3. 预处理：过滤、稀释等\n4. 指标测定：pH、浊度、COD、氨氮等\n5. 数据记录与分析\n6. 出具检测报告\n采样需代表性和均匀性', 30, NULL, 1.9166666666666667, 58, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (109, 1, '设备故障如何报修？', '设备故障报修步骤：\n1. 登录系统\n2. 进入维修管理页面\n3. 点击报修按钮\n4. 选择故障设备\n5. 详细描述故障现象\n6. 可上传故障图片\n7. 提交报修申请\n8. 等待维修人员处理', 16, NULL, 2.85, 28, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (110, 1, '如何预约设备？', '设备预约步骤：\n1. 登录系统\n2. 进入设备列表页面\n3. 选择需要预约的设备\n4. 点击预约按钮\n5. 填写预约信息（日期、时间、实验项目等）\n6. 提交预约申请\n7. 等待审核', 7, NULL, 3.31, 29, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (111, 1, '离心机如何操作？', '离心机标准操作流程：\n1. 检查离心管是否平衡，对称放置\n2. 设置转速和时间参数\n3. 关闭机盖，确保安全锁扣到位\n4. 启动离心机，等待达到设定转速\n5. 离心结束后，等待转子完全停止再开盖\n6. 小心取出样品，避免离心管破碎\n注意事项：严禁在运行时打开机盖，转子需定期保养', 18, 5, 2.75, 32, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (112, 1, '显微镜如何操作？', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 2.4000000000000004, 31, '2026-04-11 19:53:54');
