INSERT INTO `ai_chat_log` VALUES (123, 1, '我想用有机溶剂直接接触皮肤', '⚠️ 警告：化学品皮肤接触处理：\n1. 立即脱去被污染衣物\n2. 用大量流动清水冲洗\n3. 冲洗时间15分钟以上\n4. 视情况使用适当中和剂\n5. 严重者立即就医\n6. 记录接触化学品信息\n注意：不要用力擦洗皮肤', 43, NULL, 1.5833333333333333, 37, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (124, 1, '有毒化学品如何处理？', '⚠️ 安全警告：化学品溢洒处理步骤：\n1. 立即疏散人员\n2. 穿戴防护装备\n3. 围堵溢洒区域\n4. 用适当吸收材料覆盖\n5. 小心收集废液\n6. 用清水冲洗地面\n7. 废液倒入废液桶\n注意：不要直接用手接触', 41, NULL, 2.124, 25, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (125, 1, '高压灭菌锅压力上不去怎么办？', '⚠️ 安全警告：高压灭菌锅压力异常排查：\n1. 检查密封圈是否完好\n2. 检查安全阀是否堵塞\n3. 检查管路是否漏气\n4. 检查压力表是否损坏\n5. 检查加水是否足够\n6. 检查电源和加热管\n注意：严禁带故障使用', 54, 22, 4.068, 30, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (126, 1, '教我操作HPLC', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 1.5, 23, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (127, 1, '紫外分光光度计无法自检怎么解决？', '紫外分光光度计自检失败排查：\n1. 重新开关机\n2. 检查光源灯泡是否烧坏\n3. 检查样品室是否有遮挡\n4. 检查电源连接\n5. 检查仪器温度是否过高\n6. 恢复出厂设置\n仍不能解决请联系维修', 52, 18, 3.2642857142857142, 32, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (128, 1, '预约被拒绝怎么办？', '如果您的预约申请被拒绝，请：\n1. 查看审核意见了解拒绝原因\n2. 根据意见修改预约信息后重新提交\n3. 如有疑问可联系实验室管理员\n4. 尝试预约其他可用时段', 15, NULL, 2.9166666666666665, 27, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (129, 1, '设备故障如何报修？', '设备故障报修步骤：\n1. 登录系统\n2. 进入维修管理页面\n3. 点击报修按钮\n4. 选择故障设备\n5. 详细描述故障现象\n6. 可上传故障图片\n7. 提交报修申请\n8. 等待维修人员处理', 16, NULL, 2.85, 28, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (130, 1, 'HPLC色谱仪如何进行日常维护?', '⚠️ 警告：1.每次使用后清洁仪器...2,3,4,', 72, NULL, 2.33, 46, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (131, 1, '光谱仪如何校准？', '电子天平校准流程：\n1. 确保天平放置在平稳、无振动的台面\n2. 预热30分钟以上\n3. 按下CAL键进入校准模式\n4. 放置标准砝码或使用内置砝码\n5. 等待校准完成，显示零点\n6. 校准后可进行称量操作\n注意事项：称量时避免震动和气流影响', 21, 15, 1.53, 27, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (132, 1, '这个步骤需要注意什么？', '⚠️ 警告：重要安全提醒：\n1. 样品必须对称放置\n2. 离心管必须盖紧，防止样品泄漏\n3. 切勿在离心机运行时打开机盖\n4. 如有异常震动或噪音，立即停止并报修', 8, NULL, 1.428, 26, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (133, 1, '设备无法开机怎么办？', '设备故障处理流程：\n1. 立即停止使用设备\n2. 记录故障现象和发生时间\n3. 在系统中提交故障报修\n4. 保护现场，不擅自拆卸\n5. 等待维修人员处理\n6. 如影响实验可申请设备替换\n紧急情况请联系管理员', 61, NULL, 1.5214285714285716, 30, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (134, 1, '我想用高压气体检查漏气', '⚠️ 安全警告：高压容器安全使用规范：\n1. 定期检验压力容器\n2. 禁止碰撞和敲击\n3. 远离热源和易燃物\n4. 使用专用减压阀\n5. 检查管路连接是否漏气\n6. 带压时禁止拆卸\n7. 气瓶要固定放置\n注意：高压灭菌锅、高压气瓶等', 39, NULL, 1.7160000000000002, 28, '2026-04-11 19:53:54');
