INSERT INTO `ai_chat_log` VALUES (139, 2, '光、', '分光光度计操作步骤：\n1. 打开仪器电源，预热30分钟\n2. 设置测量波长\n3. 用空白溶液调零\n4. 放入样品溶液\n5. 读取吸光度或透光率\n6. 测量完毕后清洗比色皿', 4, 18, 0.6, 20, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (140, 2, '显', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 0.85, 80, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (141, 2, '如何取消预约？', '取消预约步骤：\n1. 登录系统\n2. 进入我的预约页面\n3. 找到需要取消的预约记录\n4. 点击取消按钮\n5. 选择取消原因\n6. 确认取消\n\n注意：请至少提前2小时取消，以便其他用户预约。', 14, NULL, 2.85, 20, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (142, 2, '离心机报警怎么办？', '离心机常见报警及处理：\n1. 不平衡报警 - 检查样品是否对称放置\n2. 超速报警 - 降低转速设置\n3. 门未关紧报警 - 重新关闭机盖\n4. 温度异常报警 - 检查制冷系统\n如问题持续，请立即停止使用并联系报修。', 12, 8, 3.35, 22, '2026-04-11 19:53:54');
