INSERT INTO `ai_chat_log` VALUES (145, 2, '化学品溢洒如何处理？', '⚠️ 警告：化学品溢洒处理步骤：\n1. 立即疏散人员\n2. 穿戴防护装备\n3. 围堵溢洒区域\n4. 用适当吸收材料覆盖\n5. 小心收集废液\n6. 用清水冲洗地面\n7. 废液倒入废液桶\n注意：不要直接用手接触', 41, NULL, 3.4699999999999998, 29, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (146, 2, '离心机如何操作？', '离心机标准操作流程：\n1. 检查离心管是否平衡，对称放置\n2. 设置转速和时间参数\n3. 关闭机盖，确保安全锁扣到位\n4. 启动离心机，等待达到设定转速\n5. 离心结束后，等待转子完全停止再开盖\n6. 小心取出样品，避免离心管破碎\n注意事项：严禁在运行时打开机盖，转子需定期保养', 18, 5, 2.75, 321, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (147, 2, '遇到智能冲突检测冲突怎么办？', '预约冲突解决方法：\n1. 系统会自动检测时间冲突\n2. 如有冲突可选择其他时间\n3. 可查看推荐的可替代设备\n4. 如需帮助联系管理员\n5. 避免同一时段重复预约\n建议提前规划实验时间', 59, NULL, 1.5833333333333333, 24, '2026-04-11 19:53:54');
