INSERT INTO `ai_chat_log` VALUES (153, 19, '如何预约设备？', '设备预约步骤：\n1. 登录系统\n2. 进入设备列表页面\n3. 选择需要预约的设备\n4. 点击预约按钮\n5. 填写预约信息（日期、时间、实验项目等）\n6. 提交预约申请\n7. 等待审核', 7, NULL, 3.31, 40, '2026-04-11 19:53:54');
INSERT INTO `ai_chat_log` VALUES (154, 19, '蛋白质纯化的标准流程是什么？', '蛋白质纯化基本流程：\n1. 样品准备：细胞破碎、离心取上清\n2. 盐析初步分离\n3. 离子交换层析\n4. 凝胶过滤层析\n5. 亲和层析（如需要）\n6. 透析除盐并浓缩\n7. SDS-PAGE电泳检测纯度\n每步操作后需测定蛋白浓度和活性', 27, NULL, 3.31, 29, '2026-04-11 19:53:54');
