INSERT INTO `ai_chat_log` VALUES (157, 1, '2', 'CO2培养箱操作步骤：\n1. 打开电源开关\n2. 设置温度（通常37°C）和CO2浓度（通常5%）\n3. 等待温度和CO2浓度稳定\n4. 将培养皿或培养瓶放入箱内\n5. 关闭箱门\n6. 定期观察细胞生长状态\n7. 使用完毕后记录培养情况', 5, 21, 0.5, 25, '2026-04-11 20:16:31');
INSERT INTO `ai_chat_log` VALUES (158, 9, '光学显微镜如何操作？', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 3.45, 21, '2026-04-16 03:13:13');
INSERT INTO `ai_chat_log` VALUES (159, 9, '光学显微镜如何使用？', '光学显微镜操作步骤：\n1. 打开显微镜电源，调至最低倍镜\n2. 将待观察标本放置于载物台上\n3. 使用粗调旋钮下降载物台至标本接近物镜\n4. 从目镜观察，同时缓慢上升载物台直至图像清晰\n5. 切换至高倍镜时只需微调细调旋钮\n6. 观察结束后先将载物台降至最低，关闭电源\n注意事项：不可用手直接擦拭镜头，使用专用镜头纸', 17, 1, 3.35, 11, '2026-04-16 03:13:14');
INSERT INTO `ai_chat_log` VALUES (160, 9, '电子天平使用前如何校准？', '电子天平校准流程：\n1. 确保天平放置在平稳、无振动的台面\n2. 预热30分钟以上\n3. 按下CAL键进入校准模式\n4. 放置标准砝码或使用内置砝码\n5. 等待校准完成，显示零点\n6. 校准后可进行称量操作\n注意事项：称量时避免震动和气流影响', 21, 15, 3.283333333333333, 9, '2026-04-16 03:13:15');
INSERT INTO `ai_chat_log` VALUES (161, 9, 'CO2培养箱如何使用？', 'CO2培养箱操作步骤：\n1. 打开电源开关\n2. 设置温度（通常37°C）和CO2浓度（通常5%）\n3. 等待温度和CO2浓度稳定\n4. 将培养皿或培养瓶放入箱内\n5. 关闭箱门\n6. 定期观察细胞生长状态\n7. 使用完毕后记录培养情况', 5, 21, 2.8833333333333337, 8, '2026-04-16 03:13:16');
INSERT INTO `ai_chat_log` VALUES (162, 9, '电子天平使用前如何校准？', '电子天平校准流程：\n1. 确保天平放置在平稳、无振动的台面\n2. 预热30分钟以上\n3. 按下CAL键进入校准模式\n4. 放置标准砝码或使用内置砝码\n5. 等待校准完成，显示零点\n6. 校准后可进行称量操作\n注意事项：称量时避免震动和气流影响', 21, 15, 3.283333333333333, 10, '2026-04-16 03:13:17');
INSERT INTO `ai_chat_log` VALUES (163, 9, 'PCR仪如何设置扩增程序？', 'PCR仪程序设置步骤：\n1. 打开仪器软件，新建程序\n2. 设置初始变性温度和时间（如94℃ 5min）\n3. 设置循环参数（变性94℃ 30s，退火55℃ 30s，延伸72℃ 1min）\n4. 设置循环次数（一般25-35次）\n5. 最后延伸72℃ 10min\n6. 保存程序并运行\n注意事项：试剂配制时注意避免污染', 23, 21, 3.216666666666667, 8, '2026-04-16 03:13:18');
INSERT INTO `ai_chat_log` VALUES (164, 9, '高压灭菌锅如何安全操作？', '⚠️ 安全警告：高压灭菌锅安全操作规程：\n1. 检查水位是否正常\n2. 放入待灭菌物品，不要过满\n3. 盖紧锅盖，拧紧安全螺栓\n4. 设置灭菌温度和时间（121℃ 20min）\n5. 等待压力降至零后再开盖\n6. 让物品自然冷却后取出\n注意事项：严禁带压开盖，定期检查安全阀', 24, 22, 4.02, 9, '2026-04-16 03:13:20');
INSERT INTO `ai_chat_log` VALUES (165, 9, '不戴护目镜操作离心机', '高速离心机操作步骤：\n1. 检查离心机是否平稳放置\n2. 打开机盖，将样品对称放置在转子中\n3. 确保样品管已盖紧且重量相等\n4. 关闭机盖，确保锁紧\n5. 设置转速和时间\n6. 按启动键开始离心\n7. 离心完成后等待完全停止再打开机盖', 2, 8, 2.25, 11, '2026-04-16 03:15:27');
INSERT INTO `ai_chat_log` VALUES (166, 1, '光学显微镜OM-2000如何操作？', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 3.35, 6, '2026-04-16 03:16:33');
INSERT INTO `ai_chat_log` VALUES (167, 1, '光学显微镜OM-2000如何操作？', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 1, 1, 3.35, 5, '2026-04-16 03:18:12');
