INSERT INTO `ai_chat_log` VALUES (211, 1, '这个步骤需要注意什么？', '实验室通用安全注意事项：\n1. 操作前必须仔细阅读设备操作手册\n2. 检查设备是否正常工作有无异常\n3. 确保个人防护装备佩戴齐全\n4. 了解紧急停止按钮和急救设备位置\n5. 操作时保持专注不要离开岗位\n6. 发现异常立即停止并报告\n7. 操作后清理工作区域妥善处理废弃物\n8. 认真填写使用记录', 14, NULL, 3.1999999999999997, 4, '2026-04-22 19:09:19');
