INSERT INTO `ai_chat_log` VALUES (214, 1, '原子吸收分光光度计如何操作？', '原子吸收分光光度计操作步骤：\n1. 打开仪器电源，预热30分钟\n2. 点燃空心阴极灯\n3. 调整波长和狭缝宽度\n4. 调整燃烧器高度和位置\n5. 用空白溶液调零\n6. 测量标准溶液，建立标准曲线\n7. 测量样品溶液\n8. 分析完成后关闭仪器', 11, 122, 3.016666666666667, 6, '2026-04-22 19:09:36');
