INSERT INTO `ai_chat_log` VALUES (257, 117, '高温', '⚠️ 警告：高速离心机操作步骤：\n1. 检查离心机是否平稳放置\n2. 打开机盖，将样品对称放置在转子中\n3. 确保样品管已盖紧且重量相等\n4. 关闭机盖，确保锁紧\n5. 设置转速和时间\n6. 按启动键开始离心\n7. 离心完成后等待完全停止再打开机盖\n8. 小心取出样品，避免离心管破碎', 4, 115, 0.6, 15, '2026-04-25 00:40:21');
INSERT INTO `ai_chat_log` VALUES (258, 117, '高压', '⚠️ 安全警告：⚠️ 高压灭菌锅安全操作规范：\n1. 操作前检查：\n   - 检查安全阀是否灵活，压力表是否在零位\n   - 检查密封圈是否完好，锅门关闭是否严密\n   - 确认锅内加水至规定水位线\n2. 装载规范：\n   - 物品不要堆放过密，留出蒸汽流通空间\n   - 液体容器装量不超过2/3，瓶口不要密封（用棉塞或松盖）\n   - 禁止灭菌易燃易爆物品和腐蚀性化学品\n3. 操作流程：\n   - 关门确认密封→设定温度121℃和时间20min→启动加热→排冷气→升压→灭菌→自然冷却降压→压力归零后开盖\n4. ⚠️ 严禁事项：\n   - 严禁在压力未归零时强行开盖（可能导致爆炸！）\n   - 严禁超温超压运行\n   - 严禁无人值守运行\n   - 严禁私自改装安全阀\n5. 维护保养：每周检查密封圈，每月检查安全阀，每年校验压力表', 39, NULL, 1.188, 13, '2026-04-25 00:40:43');
INSERT INTO `ai_chat_log` VALUES (259, 117, '设备在使用时出现高压', '⚠️ 安全警告：高速离心机操作步骤：\n1. 检查离心机是否平稳放置\n2. 打开机盖，将样品对称放置在转子中\n3. 确保样品管已盖紧且重量相等\n4. 关闭机盖，确保锁紧\n5. 设置转速和时间\n6. 按启动键开始离心\n7. 离心完成后等待完全停止再打开机盖\n8. 小心取出样品，避免离心管破碎', 4, 115, 1.5, 18, '2026-04-25 00:41:00');
INSERT INTO `ai_chat_log` VALUES (260, 117, '设备在使用时出现高温', '⚠️ 警告：高速离心机操作步骤：\n1. 检查离心机是否平稳放置\n2. 打开机盖，将样品对称放置在转子中\n3. 确保样品管已盖紧且重量相等\n4. 关闭机盖，确保锁紧\n5. 设置转速和时间\n6. 按启动键开始离心\n7. 离心完成后等待完全停止再打开机盖\n8. 小心取出样品，避免离心管破碎', 4, 115, 1.5, 16, '2026-04-25 00:41:12');
INSERT INTO `ai_chat_log` VALUES (261, 117, '显微镜出现高温', '显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察标本放置在载物台上\n3. 使用粗调旋钮调节焦距，使标本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', 8, 119, 2.05, 16, '2026-04-25 00:41:46');
INSERT INTO `ai_chat_log` VALUES (262, 117, '可以用手直接接触有机溶剂吗？', '⚠️ 警告：⚠️ 绝对不可以！有机溶剂直接接触皮肤的危害：\n\n1. 大多数有机溶剂可通过皮肤吸收导致中毒\n2. 可能引起皮肤过敏红肿化学灼伤\n3. 部分溶剂具有致癌风险\n4. 长期接触可能导致神经系统损伤\n\n正确做法：\n- 必须佩戴耐化学腐蚀手套\n- 在通风橱内操作\n- 皮肤接触后立即用大量清水冲洗15分钟\n- 如有不适立即就医', 16, NULL, 3.321428571428571, 18, '2026-04-25 00:41:57');
INSERT INTO `ai_chat_log` VALUES (263, 117, '这个步骤需要注意什么？', '实验室通用安全注意事项：\n1. 操作前必须仔细阅读设备操作手册\n2. 检查设备是否正常工作有无异常\n3. 确保个人防护装备佩戴齐全\n4. 了解紧急停止按钮和急救设备位置\n5. 操作时保持专注不要离开岗位\n6. 发现异常立即停止并报告\n7. 操作后清理工作区域妥善处理废弃物\n8. 认真填写使用记录', 14, NULL, 3.1999999999999997, 19, '2026-04-25 00:41:59');
