INSERT INTO `ai_chat_log` VALUES (269, 1, '高速离心机如何操作？', '⚠️ 警告：高速离心机操作步骤：\n1. 检查离心机是否平稳放置\n2. 打开机盖，将样品对称放置在转子中\n3. 确保样品管已盖紧且重量相等\n4. 关闭机盖，确保锁紧\n5. 设置转速和时间\n6. 按启动键开始离心\n7. 离心完成后等待完全停止再打开机盖\n8. 小心取出样品，避免离心管破碎', 4, 115, 3.45, 15, '2026-04-25 03:26:14');
