INSERT INTO `ai_chat_log` VALUES (274, 117, '高压设备有什么危险？', '⚠️ 安全警告：⚠️ 安全警告：设备漏电属于紧急危险情况！\n\n漏电处理步骤：\n1. 立即断电：不要触碰设备金属外壳！先断开电源插头或拉下空气开关\n2. 人员安全：如有人触电，切勿直接拉拽！用干燥木棒或绝缘物将人与电源分离，拨打120急救\n3. 标识警示：在设备上张贴\"漏电危险 禁止使用\"标识，通知实验室管理人员\n4. 排查原因：\n   - 检查电源线绝缘层是否破损老化\n   - 检查设备内部是否有液体泼洒导致短路\n   - 检查接地线是否断开或接触不良\n   - 检查插头插座是否进水或氧化\n5. 绝缘测试：用兆欧表（绝缘电阻测试仪）测量设备绝缘电阻，应≥2MΩ\n6. 维修确认：由专业维修人员修复后，再次测量绝缘电阻合格方可重新使用\n\n⚠️ 严禁带电操作！严禁用水灭火！严禁私自拆修！', 35, NULL, 1.74, 56, '2026-04-25 09:02:17');
