INSERT INTO `knowledge_base` VALUES (1, '设备操作手册', 1, '光学显微镜OM-2000如何操作？', '光学显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察样本放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', '显微镜,光学显微镜,操作', 0, 'IMAGE', '[\"/uploads/device/e25dccc5c1d0412baa6a4566b15a8d23.jpg\"]', '[{\"step\":1,\"title\":\"打开电源\",\"content\":\"打开显微镜电源开关，确保电源连接正常\",\"image\":\"/api/uploads/device/0054596f501d45b1a6fd14371110c1b9.jpg\"},{\"step\":2,\"title\":\"放置样本\",\"content\":\"将待观察样本放置在载物台上，固定好样本\",\"image\":\"/api/uploads/device/cd896d0d6316425498f0b60babc406c5.jpg\"},{\"step\":3,\"title\":\"粗调焦距\",\"content\":\"使用粗调旋钮调节焦距，使样本初步清晰\",\"image\":\"/api/uploads/device/2e4769afa0a84f6995fb0ec647d9a3b0.jpg\"},{\"step\":4,\"title\":\"细调焦距\",\"content\":\"使用细调旋钮调节至最清晰，获得最佳观察效果\",\"image\":\"/api/uploads/device/c5c7a3840eb24198a17d0215b139067b.jpg\"},{\"step\":5,\"title\":\"选择放大倍数\",\"content\":\"选择合适的目镜和物镜倍数，根据观察需求调整\",\"image\":\"/uploads/device/e25dccc5c1d0412baa6a4566b15a8d23.jpg\"},{\"step\":6,\"title\":\"观察记录\",\"content\":\"观察并记录结果，可使用数码摄像头拍照\",\"image\":\"/api/uploads/device/bbb25085e9c54c5696d18e8586b69f41.jpg\"},{\"step\":7,\"title\":\"关闭清理\",\"content\":\"使用完毕后关闭电源，清理载物台，保持设备整洁\",\"image\":\"/api/uploads/device/f5b21b3b79e1443685130803314ae8f0.jpg\"}]', 10, 1, 1, '2026-04-16 03:16:22', '2026-04-16 03:17:25', 0);
INSERT INTO `knowledge_base` VALUES (2, '设备操作手册', 113, '倒置显微镜如何操作？', '倒置显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将细胞培养皿放置在载物台上\n3. 使用粗调旋钮调节焦距，使样本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的物镜倍数\n6. 观察并记录细胞生长状态\n7. 使用完毕后关闭电源，清理载物台', '倒置显微镜,细胞培养,操作', 0, 'IMAGE', '[\"/uploads/device/f12e2ee980c446b6ade52d6505e093e3.jpg\"]', '[{\"step\":1,\"title\":\"打开显微镜电源开关\",\"content\":\"打开显微镜电源开关，确保电源连接正常\",\"image\":\"/uploads/device/f12e2ee980c446b6ade52d6505e093e3.jpg\"},{\"step\":2,\"title\":\"放置细胞培养皿\",\"content\":\"将细胞培养皿小心放置在载物台上，确保位置正确\",\"image\":\"/uploads/device/f12e2ee980c446b6ade52d6505e093e3.jpg\"},{\"step\":3,\"title\":\"粗调焦距\",\"content\":\"使用粗调旋钮调节焦距，使样本初步清晰\",\"image\":\"/uploads/device/f12e2ee980c446b6ade52d6505e093e3.jpg\"},{\"step\":4,\"title\":\"细调焦距\",\"content\":\"使用细调旋钮调节至最清晰，获得最佳观察效果\",\"image\":\"/uploads/device/f12e2ee980c446b6ade52d6505e093e3.jpg\"},{\"step\":5,\"title\":\"选择物镜倍数\",\"content\":\"根据需要选择合适的物镜倍数，通常从低倍开始\",\"image\":\"/uploads/device/f12e2ee980c446b6ade52d6505e093e3.jpg\"},{\"step\":6,\"title\":\"观察记录\",\"content\":\"观察并记录细胞生长状态，可使用数码摄像头拍照\",\"image\":\"/uploads/device/f12e2ee980c446b6ade52d6505e093e3.jpg\"},{\"step\":7,\"title\":\"关闭清理\",\"content\":\"使用完毕后关闭电源，清理载物台，保持设备整洁\",\"image\":\"/uploads/device/f12e2ee980c446b6ade52d6505e093e3.jpg\"}]', 10, 2, 1, '2026-04-16 03:16:22', '2026-04-16 03:16:22', 0);
INSERT INTO `knowledge_base` VALUES (3, '设备操作手册', 114, '二氧化碳培养箱如何使用？', '二氧化碳培养箱操作步骤：\n1. 打开电源开关\n2. 设置温度（通常37°C）和CO2浓度（通常5%）\n3. 等待温度和CO2浓度稳定\n4. 将培养皿或培养瓶放入箱内\n5. 关闭箱门\n6. 定期观察细胞生长状态\n7. 使用完毕后记录培养情况', '培养箱,CO2培养箱,细胞培养', 0, 'IMAGE', '[\"/uploads/device/d99194af22b34a80b48d3f54e3054e5f.jpg\"]', '[{\"step\":1,\"title\":\"打开电源开关\",\"content\":\"打开CO2培养箱电源开关，确保电源连接正常\",\"image\":\"/uploads/device/d99194af22b34a80b48d3f54e3054e5f.jpg\"},{\"step\":2,\"title\":\"设置参数\",\"content\":\"设置温度（通常37°C）和CO2浓度（通常5%）\",\"image\":\"/uploads/device/d99194af22b34a80b48d3f54e3054e5f.jpg\"},{\"step\":3,\"title\":\"等待稳定\",\"content\":\"等待温度和CO2浓度稳定，通常需要30分钟\",\"image\":\"/uploads/device/d99194af22b34a80b48d3f54e3054e5f.jpg\"},{\"step\":4,\"title\":\"放入样本\",\"content\":\"将培养皿或培养瓶放入箱内，注意保持清洁\",\"image\":\"/uploads/device/d99194af22b34a80b48d3f54e3054e5f.jpg\"},{\"step\":5,\"title\":\"关闭箱门\",\"content\":\"关闭箱门，确保密封良好\",\"image\":\"/uploads/device/d99194af22b34a80b48d3f54e3054e5f.jpg\"},{\"step\":6,\"title\":\"定期观察\",\"content\":\"定期观察细胞生长状态，记录相关数据\",\"image\":\"/uploads/device/d99194af22b34a80b48d3f54e3054e5f.jpg\"},{\"step\":7,\"title\":\"记录情况\",\"content\":\"使用完毕后记录培养情况，便于后续分析\",\"image\":\"/uploads/device/d99194af22b34a80b48d3f54e3054e5f.jpg\"}]', 15, 3, 1, '2026-04-16 03:16:22', '2026-04-16 03:16:22', 0);
INSERT INTO `knowledge_base` VALUES (4, '设备操作手册', 115, '高速离心机如何操作？', '高速离心机操作步骤：\n1. 检查离心机是否平稳放置\n2. 打开机盖，将样品对称放置在转子中\n3. 确保样品管已盖紧且重量相等\n4. 关闭机盖，确保锁紧\n5. 设置转速和时间\n6. 按启动键开始离心\n7. 离心完成后等待完全停止再打开机盖\n8. 小心取出样品，避免离心管破碎', '离心机,高速离心机,操作', 1, 'IMAGE', '[\"/uploads/device/de15ea7a50b24322bbe1bc470333b496.jpg\"]', '[{\"step\":1,\"title\":\"检查设备状态\",\"content\":\"检查离心机是否平稳放置，确保周围无障碍物\",\"image\":\"/uploads/device/de15ea7a50b24322bbe1bc470333b496.jpg\"},{\"step\":2,\"title\":\"放置样品\",\"content\":\"打开机盖，将样品对称放置在转子中，确保平衡\",\"image\":\"/uploads/device/de15ea7a50b24322bbe1bc470333b496.jpg\"},{\"step\":3,\"title\":\"检查样品管\",\"content\":\"确保样品管已盖紧且重量相等，避免离心时失衡\",\"image\":\"/uploads/device/de15ea7a50b24322bbe1bc470333b496.jpg\"},{\"step\":4,\"title\":\"关闭机盖\",\"content\":\"关闭机盖，确保锁紧，防止离心过程中打开\",\"image\":\"/uploads/device/de15ea7a50b24322bbe1bc470333b496.jpg\"},{\"step\":5,\"title\":\"设置参数\",\"content\":\"设置转速和时间，根据样品类型选择合适参数\",\"image\":\"/uploads/device/de15ea7a50b24322bbe1bc470333b496.jpg\"},{\"step\":6,\"title\":\"启动离心\",\"content\":\"按启动键开始离心，观察设备运行状态\",\"image\":\"/uploads/device/de15ea7a50b24322bbe1bc470333b496.jpg\"},{\"step\":7,\"title\":\"等待停止\",\"content\":\"离心完成后等待完全停止再打开机盖，切勿强行开盖\",\"image\":\"/uploads/device/de15ea7a50b24322bbe1bc470333b496.jpg\"},{\"step\":8,\"title\":\"取出样品\",\"content\":\"小心取出样品，避免离心管破碎，清理设备\",\"image\":\"/uploads/device/de15ea7a50b24322bbe1bc470333b496.jpg\"}]', 10, 4, 1, '2026-04-16 03:16:22', '2026-04-16 03:16:22', 0);
INSERT INTO `knowledge_base` VALUES (5, '设备操作手册', 116, '高效液相色谱仪如何操作？', '高效液相色谱仪操作步骤：\n1. 打开仪器电源，预热30分钟\n2. 启动泵，冲洗色谱柱\n3. 设置流动相比例和流速\n4. 注入标准溶液，建立标准曲线\n5. 注入样品溶液\n6. 记录色谱图和数据\n7. 分析完成后冲洗色谱柱\n8. 关闭仪器电源', '色谱仪,高效液相色谱,操作', 0, 'IMAGE', '[\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"]', '[{\"step\":1,\"title\":\"打开电源预热\",\"content\":\"打开仪器电源，预热30分钟，确保仪器稳定\",\"image\":\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"},{\"step\":2,\"title\":\"冲洗色谱柱\",\"content\":\"启动泵，冲洗色谱柱，去除残留杂质\",\"image\":\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"},{\"step\":3,\"title\":\"设置流动相\",\"content\":\"设置流动相比例和流速，根据实验要求调整\",\"image\":\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"},{\"step\":4,\"title\":\"建立标准曲线\",\"content\":\"注入标准溶液，建立标准曲线，用于定量分析\",\"image\":\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"},{\"step\":5,\"title\":\"注入样品\",\"content\":\"注入样品溶液，开始分析\",\"image\":\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"},{\"step\":6,\"title\":\"记录数据\",\"content\":\"记录色谱图和数据，保存分析结果\",\"image\":\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"},{\"step\":7,\"title\":\"冲洗色谱柱\",\"content\":\"分析完成后冲洗色谱柱，延长柱寿命\",\"image\":\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"},{\"step\":8,\"title\":\"关闭电源\",\"content\":\"关闭仪器电源，清理实验台\",\"image\":\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"}]', 20, 5, 1, '2026-04-16 03:16:22', '2026-04-16 03:16:22', 0);
INSERT INTO `knowledge_base` VALUES (6, '设备操作手册', 117, '数字示波器如何操作？', '数字示波器操作步骤：\n1. 打开示波器电源，预热5分钟\n2. 连接测试探头到信号源\n3. 设置垂直灵敏度和水平扫描时间\n4. 调整触发模式和电平\n5. 观察波形，调整波形位置和大小\n6. 使用测量功能测量电压、频率等参数\n7. 保存波形数据（如需）\n8. 关闭示波器电源', '示波器,数字示波器,电子测量', 0, 'IMAGE', '[\"/uploads/device/d2ab6ab18f644e6e9b063a500655be1e.jpg\"]', '[{\"step\":1,\"title\":\"打开电源预热\",\"content\":\"打开示波器电源，预热5分钟，确保仪器稳定\",\"image\":\"/api/uploads/device/3017f633d8db430bbe75bcaf3a2d478e.jpg\"},{\"step\":2,\"title\":\"连接测试探头\",\"content\":\"连接测试探头到信号源，确保连接牢固\",\"image\":\"/api/uploads/device/e8be5a952698428f8e963bc1965cfeda.jpg\"},{\"step\":3,\"title\":\"设置垂直和水平参数\",\"content\":\"设置垂直灵敏度和水平扫描时间，根据信号特性调整\",\"image\":\"/api/uploads/device/ee469a1e5e5241188e92f54c7ab70e33.jpg\"},{\"step\":4,\"title\":\"调整触发设置\",\"content\":\"调整触发模式和电平，使波形稳定显示\",\"image\":\"/api/uploads/device/1153c5a4f717447289a0279653d1c33a.jpg\"},{\"step\":5,\"title\":\"观察调整波形\",\"content\":\"观察波形，调整波形位置和大小，获得清晰显示\",\"image\":\"/api/uploads/device/ada7b25a30b04e2687a1376463a55cbd.jpg\"},{\"step\":6,\"title\":\"测量参数\",\"content\":\"使用测量功能测量电压、频率等参数，记录数据\",\"image\":\"/api/uploads/device/6ad97ff2eb2746b9b350bc512e099aec.jpg\"},{\"step\":7,\"title\":\"保存数据\",\"content\":\"保存波形数据（如需），便于后续分析\",\"image\":\"/api/uploads/device/f3703a90ccee437e8f151cf602246909.jpg\"},{\"step\":8,\"title\":\"关闭电源\",\"content\":\"关闭示波器电源，整理测试探头\",\"image\":\"/uploads/device/d2ab6ab18f644e6e9b063a500655be1e.jpg\"}]', 15, 6, 1, '2026-04-16 03:16:22', '2026-04-16 03:18:07', 0);
INSERT INTO `knowledge_base` VALUES (7, '设备操作手册', 118, '数字万用表如何使用？', '数字万用表操作步骤：\n1. 打开万用表电源\n2. 根据测量需求选择合适的测量模式\n3. 选择合适的量程\n4. 将测试表笔连接到相应的插孔\n5. 将表笔接触测量点\n6. 读取测量值\n7. 测量完成后将量程调至最高档\n8. 关闭万用表电源', '万用表,数字万用表,电子测量', 0, 'IMAGE', '[\"/uploads/device/20ccaabb7aff4ce9ba2c53116a1fbf0b.jpg\"]', '[{\"step\":1,\"title\":\"打开电源\",\"content\":\"打开万用表电源，检查电池电量是否充足\",\"image\":\"/uploads/device/20ccaabb7aff4ce9ba2c53116a1fbf0b.jpg\"},{\"step\":2,\"title\":\"选择测量模式\",\"content\":\"根据测量需求选择合适的测量模式（电压、电流、电阻等）\",\"image\":\"/uploads/device/20ccaabb7aff4ce9ba2c53116a1fbf0b.jpg\"},{\"step\":3,\"title\":\"选择量程\",\"content\":\"选择合适的量程，确保测量值在量程范围内\",\"image\":\"/uploads/device/20ccaabb7aff4ce9ba2c53116a1fbf0b.jpg\"},{\"step\":4,\"title\":\"连接表笔\",\"content\":\"将测试表笔连接到相应的插孔，红表笔接正极，黑表笔接负极\",\"image\":\"/uploads/device/20ccaabb7aff4ce9ba2c53116a1fbf0b.jpg\"},{\"step\":5,\"title\":\"接触测量点\",\"content\":\"将表笔接触测量点，确保接触良好\",\"image\":\"/uploads/device/20ccaabb7aff4ce9ba2c53116a1fbf0b.jpg\"},{\"step\":6,\"title\":\"读取测量值\",\"content\":\"读取测量值，记录数据\",\"image\":\"/uploads/device/20ccaabb7aff4ce9ba2c53116a1fbf0b.jpg\"},{\"step\":7,\"title\":\"调整量程\",\"content\":\"测量完成后将量程调至最高档，保护万用表\",\"image\":\"/uploads/device/20ccaabb7aff4ce9ba2c53116a1fbf0b.jpg\"},{\"step\":8,\"title\":\"关闭电源\",\"content\":\"关闭万用表电源，整理测试表笔\",\"image\":\"/uploads/device/20ccaabb7aff4ce9ba2c53116a1fbf0b.jpg\"}]', 10, 7, 1, '2026-04-16 03:16:22', '2026-04-16 03:16:22', 0);
INSERT INTO `knowledge_base` VALUES (8, '设备操作手册', 119, '显微镜如何操作？', '显微镜操作步骤：\n1. 打开显微镜电源开关\n2. 将待观察标本放置在载物台上\n3. 使用粗调旋钮调节焦距，使标本初步清晰\n4. 使用细调旋钮调节至最清晰\n5. 选择合适的目镜和物镜倍数\n6. 观察并记录结果\n7. 使用完毕后关闭电源，清理载物台', '显微镜,生物显微镜,操作', 0, 'IMAGE', '[\"/uploads/device/221fbad4be134cc1ad2ff6a8c863d8cb.jpg\"]', '[{\"step\":1,\"title\":\"打开电源\",\"content\":\"打开显微镜电源开关，确保电源连接正常\",\"image\":\"/uploads/device/221fbad4be134cc1ad2ff6a8c863d8cb.jpg\"},{\"step\":2,\"title\":\"放置标本\",\"content\":\"将待观察标本放置在载物台上，固定好标本\",\"image\":\"/uploads/device/221fbad4be134cc1ad2ff6a8c863d8cb.jpg\"},{\"step\":3,\"title\":\"粗调焦距\",\"content\":\"使用粗调旋钮调节焦距，使标本初步清晰\",\"image\":\"/uploads/device/221fbad4be134cc1ad2ff6a8c863d8cb.jpg\"},{\"step\":4,\"title\":\"细调焦距\",\"content\":\"使用细调旋钮调节至最清晰，获得最佳观察效果\",\"image\":\"/uploads/device/221fbad4be134cc1ad2ff6a8c863d8cb.jpg\"},{\"step\":5,\"title\":\"选择放大倍数\",\"content\":\"选择合适的目镜和物镜倍数，根据观察需求调整\",\"image\":\"/uploads/device/221fbad4be134cc1ad2ff6a8c863d8cb.jpg\"},{\"step\":6,\"title\":\"观察记录\",\"content\":\"观察并记录结果，可使用数码摄像头拍照\",\"image\":\"/uploads/device/221fbad4be134cc1ad2ff6a8c863d8cb.jpg\"},{\"step\":7,\"title\":\"关闭清理\",\"content\":\"使用完毕后关闭电源，清理载物台，保持设备整洁\",\"image\":\"/uploads/device/221fbad4be134cc1ad2ff6a8c863d8cb.jpg\"}]', 10, 8, 1, '2026-04-16 03:16:22', '2026-04-16 03:16:22', 0);
INSERT INTO `knowledge_base` VALUES (9, '设备操作手册', 120, '信号发生器如何操作？', '信号发生器操作步骤：\n1. 打开信号发生器电源\n2. 选择信号类型（正弦波、方波等）\n3. 设置信号频率\n4. 设置信号 amplitude\n5. 连接输出到测试电路\n6. 开启信号输出\n7. 调整参数直到获得所需信号\n8. 测试完成后关闭输出，关闭电源', '信号发生器,电子测试,信号源', 0, 'IMAGE', '[\"/uploads/device/300ae331a26541c49a4bc2b447fdec08.jpg\"]', '[{\"step\":1,\"title\":\"打开电源\",\"content\":\"打开信号发生器电源，检查设备是否正常启动\",\"image\":\"/uploads/device/300ae331a26541c49a4bc2b447fdec08.jpg\"},{\"step\":2,\"title\":\"选择信号类型\",\"content\":\"选择信号类型（正弦波、方波、三角波等）\",\"image\":\"/uploads/device/300ae331a26541c49a4bc2b447fdec08.jpg\"},{\"step\":3,\"title\":\"设置频率\",\"content\":\"设置信号频率，根据测试需求调整\",\"image\":\"/uploads/device/300ae331a26541c49a4bc2b447fdec08.jpg\"},{\"step\":4,\"title\":\"设置幅度\",\"content\":\"设置信号幅度（amplitude），确保输出合适的电压\",\"image\":\"/uploads/device/300ae331a26541c49a4bc2b447fdec08.jpg\"},{\"step\":5,\"title\":\"连接输出\",\"content\":\"连接输出到测试电路，确保连接正确\",\"image\":\"/uploads/device/300ae331a26541c49a4bc2b447fdec08.jpg\"},{\"step\":6,\"title\":\"开启输出\",\"content\":\"开启信号输出，开始测试\",\"image\":\"/uploads/device/300ae331a26541c49a4bc2b447fdec08.jpg\"},{\"step\":7,\"title\":\"调整参数\",\"content\":\"调整参数直到获得所需信号，观察测试结果\",\"image\":\"/uploads/device/300ae331a26541c49a4bc2b447fdec08.jpg\"},{\"step\":8,\"title\":\"关闭设备\",\"content\":\"测试完成后关闭输出，关闭电源，整理测试线缆\",\"image\":\"/uploads/device/300ae331a26541c49a4bc2b447fdec08.jpg\"}]', 15, 9, 1, '2026-04-16 03:16:22', '2026-04-16 03:16:22', 0);
INSERT INTO `knowledge_base` VALUES (10, '设备操作手册', 121, '旋转蒸发仪如何操作？', '旋转蒸发仪操作步骤：\n1. 连接冷凝水和真空泵\n2. 将样品放入蒸馏瓶中\n3. 将蒸馏瓶连接到旋转蒸发仪\n4. 设置水浴温度和旋转速度\n5. 开启旋转和真空泵\n6. 观察蒸馏过程\n7. 蒸馏完成后关闭真空泵\n8. 关闭旋转，取出样品\n9. 关闭水浴，清理仪器', '旋转蒸发仪,蒸馏,浓缩', 1, 'IMAGE', '[\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"]', '[{\"step\":1,\"title\":\"连接设备\",\"content\":\"连接冷凝水和真空泵，确保连接紧密无泄漏\",\"image\":\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"},{\"step\":2,\"title\":\"放入样品\",\"content\":\"将样品放入蒸馏瓶中，注意不要超过瓶容量的1/3\",\"image\":\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"},{\"step\":3,\"title\":\"连接蒸馏瓶\",\"content\":\"将蒸馏瓶连接到旋转蒸发仪，确保密封良好\",\"image\":\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"},{\"step\":4,\"title\":\"设置参数\",\"content\":\"设置水浴温度和旋转速度，根据样品特性调整\",\"image\":\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"},{\"step\":5,\"title\":\"开启设备\",\"content\":\"开启旋转和真空泵，开始蒸馏过程\",\"image\":\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"},{\"step\":6,\"title\":\"观察蒸馏\",\"content\":\"观察蒸馏过程，注意馏出液的情况\",\"image\":\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"},{\"step\":7,\"title\":\"关闭真空泵\",\"content\":\"蒸馏完成后关闭真空泵，防止倒吸\",\"image\":\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"},{\"step\":8,\"title\":\"取出样品\",\"content\":\"关闭旋转，取出样品，注意高温烫伤\",\"image\":\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"},{\"step\":9,\"title\":\"清理仪器\",\"content\":\"关闭水浴，清理仪器，保持设备整洁\",\"image\":\"/uploads/device/51d37de1526a44a0855aa72c33625cb5.jpg\"}]', 20, 10, 1, '2026-04-16 03:16:22', '2026-04-16 03:16:22', 0);
INSERT INTO `knowledge_base` VALUES (11, '设备操作手册', 122, '原子吸收分光光度计如何操作？', '原子吸收分光光度计操作步骤：\n1. 打开仪器电源，预热30分钟\n2. 点燃空心阴极灯\n3. 调整波长和狭缝宽度\n4. 调整燃烧器高度和位置\n5. 用空白溶液调零\n6. 测量标准溶液，建立标准曲线\n7. 测量样品溶液\n8. 分析完成后关闭仪器', '原子吸收,分光光度计,元素分析', 0, 'IMAGE', '[\"/uploads/device/75d2774256b84b09b161ed015f42cf03.jpg\"]', '[{\"step\":1,\"title\":\"打开电源预热\",\"content\":\"打开仪器电源，预热30分钟，确保仪器稳定\",\"image\":\"/uploads/device/75d2774256b84b09b161ed015f42cf03.jpg\"},{\"step\":2,\"title\":\"点燃空心阴极灯\",\"content\":\"点燃空心阴极灯，选择合适的元素灯\",\"image\":\"/uploads/device/75d2774256b84b09b161ed015f42cf03.jpg\"},{\"step\":3,\"title\":\"调整波长和狭缝\",\"content\":\"调整波长和狭缝宽度，选择最佳分析条件\",\"image\":\"/uploads/device/75d2774256b84b09b161ed015f42cf03.jpg\"},{\"step\":4,\"title\":\"调整燃烧器\",\"content\":\"调整燃烧器高度和位置，优化火焰条件\",\"image\":\"/uploads/device/75d2774256b84b09b161ed015f42cf03.jpg\"},{\"step\":5,\"title\":\"空白溶液调零\",\"content\":\"用空白溶液调零，消除背景干扰\",\"image\":\"/uploads/device/75d2774256b84b09b161ed015f42cf03.jpg\"},{\"step\":6,\"title\":\"建立标准曲线\",\"content\":\"测量标准溶液，建立标准曲线，用于定量分析\",\"image\":\"/uploads/device/75d2774256b84b09b161ed015f42cf03.jpg\"},{\"step\":7,\"title\":\"测量样品\",\"content\":\"测量样品溶液，读取吸光度值\",\"image\":\"/uploads/device/75d2774256b84b09b161ed015f42cf03.jpg\"},{\"step\":8,\"title\":\"关闭仪器\",\"content\":\"分析完成后关闭仪器，清理实验台\",\"image\":\"/uploads/device/75d2774256b84b09b161ed015f42cf03.jpg\"}]', 25, 11, 1, '2026-04-16 03:16:22', '2026-04-16 03:16:22', 0);
INSERT INTO `knowledge_base` VALUES (12, '设备操作手册', 1, '显微镜如何校准？', '显微镜校准操作步骤：\n1. 打开显微镜电源开关，预热5分钟\n2. 清洁物镜和目镜镜头表面\n3. 将载物台降至最低位置\n4. 选择10倍低倍物镜\n5. 放置标准玻片标本\n6. 调节粗调旋钮使图像清晰\n7. 切换到目标倍率物镜重新对焦\n8. 校准完成后记录参数', '显微镜,校准,调节,对焦,操作', 0, 'TEXT', NULL, NULL, 8, 100, 1, '2026-04-16 03:29:37', '2026-04-16 03:29:37', 0);
INSERT INTO `knowledge_base` VALUES (13, '设备操作手册', 18, '光谱仪如何校准？', '分光光度计校准步骤：\n1. 开机预热30分钟确保光源稳定\n2. 准备空白参比溶液放入比色皿\n3. 设置测量波长\n4. 按调零键使吸光度归零\n5. 确认透光率为100%\n6. 如需多点校准建立标准曲线\n7. 记录校准时间和参数\n8. 定期检查校准状态', '光谱仪,校准,调零,波长,分光光度计', 0, 'IMAGE', NULL, '[{\"step\":1,\"title\":\"预热仪器\",\"content\":\"打开电源预热30分钟\",\"image\":\"/uploads/device/557025d48b944ef59fd10d1d5e57a24c.jpg\"},{\"step\":2,\"title\":\"准备空白溶液\",\"content\":\"准备空白参比溶液\"},{\"step\":3,\"title\":\"设置波长\",\"content\":\"选择合适测量波长\"},{\"step\":4,\"title\":\"调零操作\",\"content\":\"空白溶液调零\"},{\"step\":5,\"title\":\"确认校准\",\"content\":\"确认读数正确\"}]', 10, 101, 1, '2026-04-16 03:29:37', '2026-04-16 03:29:37', 0);
INSERT INTO `knowledge_base` VALUES (14, '安全规范', NULL, '这个步骤需要注意什么？', '实验室通用安全注意事项：\n1. 操作前必须仔细阅读设备操作手册\n2. 检查设备是否正常工作有无异常\n3. 确保个人防护装备佩戴齐全\n4. 了解紧急停止按钮和急救设备位置\n5. 操作时保持专注不要离开岗位\n6. 发现异常立即停止并报告\n7. 操作后清理工作区域妥善处理废弃物\n8. 认真填写使用记录', '注意,事项,安全,防护,注意事项,实验室安全', 0, 'TEXT', NULL, '[{\"step\":1,\"title\":\"阅读手册\",\"content\":\"操作前仔细阅读设备操作手册\"},{\"step\":2,\"title\":\"检查设备\",\"content\":\"确认设备正常工作\"},{\"step\":3,\"title\":\"防护装备\",\"content\":\"确保个人防护装备齐全\"},{\"step\":4,\"title\":\"了解应急\",\"content\":\"了解紧急停止按钮位置\"},{\"step\":5,\"title\":\"专注操作\",\"content\":\"保持专注不离开岗位\"}]', 10, 200, 1, '2026-04-16 03:29:37', '2026-04-16 03:29:37', 0);
INSERT INTO `knowledge_base` VALUES (15, '故障排查', NULL, '设备无法开机怎么办？', '设备无法开机故障排查步骤：\n1. 检查电源插头是否插紧插座是否有电\n2. 检查电源开关是否处于开启位置\n3. 检查保险丝是否熔断必要时更换同规格保险丝\n4. 检查设备电源线是否损坏或断裂\n5. 尝试重启设备关闭后等待30秒再开启\n6. 查看设备显示屏是否有错误代码提示\n7. 参考说明书对照错误代码查找原因\n8. 如以上方法无效请联系设备维护人员报修', '故障,无法开机,排查,维修,报修,电源', 0, 'TEXT', NULL, '[{\"step\":1,\"title\":\"检查电源\",\"content\":\"检查插头是否插紧插座是否有电\"},{\"step\":2,\"title\":\"检查开关\",\"content\":\"确认电源开关开启\"},{\"step\":3,\"title\":\"检查保险丝\",\"content\":\"必要时更换同规格保险丝\"},{\"step\":4,\"title\":\"尝试重启\",\"content\":\"关闭等待30秒后再开\"},{\"step\":5,\"title\":\"查看错误码\",\"content\":\"对照说明书查找原因\"},{\"step\":6,\"title\":\"联系报修\",\"content\":\"联系设备维护人员\"}]', 10, 300, 1, '2026-04-16 03:29:37', '2026-04-16 03:29:37', 0);
INSERT INTO `knowledge_base` VALUES (16, '安全规范', NULL, '可以用手直接接触有机溶剂吗？', '⚠️ 绝对不可以！有机溶剂直接接触皮肤的危害：\n\n1. 大多数有机溶剂可通过皮肤吸收导致中毒\n2. 可能引起皮肤过敏红肿化学灼伤\n3. 部分溶剂具有致癌风险\n4. 长期接触可能导致神经系统损伤\n\n正确做法：\n- 必须佩戴耐化学腐蚀手套\n- 在通风橱内操作\n- 皮肤接触后立即用大量清水冲洗15分钟\n- 如有不适立即就医', '有机溶剂,皮肤,接触,危险,警告,中毒', 1, 'TEXT', NULL, NULL, 5, 400, 1, '2026-04-16 03:29:37', '2026-04-16 03:29:37', 0);
INSERT INTO `knowledge_base` VALUES (17, '安全规范', 8, '可以不戴护目镜操作离心机吗？', '🚨 危险！不戴护目镜操作离心机的严重后果：\n\n1. 离心过程中试管破裂可能导致玻璃碎片飞溅\n2. 化学品泄漏可能溅入眼睛造成失明\n3. 样品气溶胶可能携带病原微生物\n4. 高速旋转产生的气溶胶可被吸入肺部\n\n强制要求：\n- 操作离心机必须佩戴护目镜\n- 建议同时佩戴防护面罩\n- 生物危害样品需在生物安全柜内操作\n- 发生眼部异物立即用洗眼器冲洗并就医', '离心机,护目镜,危险,眼睛,安全,禁止,不戴', 1, 'TEXT', NULL, NULL, 5, 401, 1, '2026-04-16 03:29:37', '2026-04-16 03:29:37', 0);
INSERT INTO `knowledge_base` VALUES (18, '安全规范', 125, '测试测试', '测试测试', '测试，11111', 1, 'TEXT', NULL, '', 4, 0, 0, '2026-04-23 02:31:30', '2026-04-23 02:33:25', 1);
INSERT INTO `knowledge_base` VALUES (19, '实验流程', NULL, '细胞培养实验的标准流程是什么？', '细胞培养实验标准流程：\n1. 实验前准备：检查CO2培养箱温度（37℃）和CO2浓度（5%），确认培养基pH和颜色正常\n2. 细胞复苏：从液氮罐取出冻存管，37℃水浴快速融化（1-2分钟内），转移至15mL离心管，加入9mL预热培养基，1000rpm离心5分钟\n3. 细胞传代：吸弃旧培养基，PBS洗涤1-2次，加入0.25%胰蛋白酶消化1-3分钟，显微镜下观察细胞形态变圆后加入含血清培养基终止消化\n4. 细胞计数：取10μL细胞悬液与10μL台盼蓝混合，血球计数板计数，计算活细胞浓度\n5. 接种培养：按所需密度接种至培养瓶/板，加入适量培养基，放入CO2培养箱\n6. 日常观察：每天显微镜观察细胞形态和密度，记录生长状态\n7. 换液：根据细胞生长速度，每2-3天更换一次培养基', '细胞培养,传代,复苏,CO2培养箱,胰蛋白酶,细胞计数', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"实验前准备\",\"content\":\"检查CO2培养箱温度（37℃）和CO2浓度（5%），确认培养基pH和颜色正常\",\"duration\":10},{\"stepNumber\":2,\"title\":\"细胞复苏\",\"content\":\"从液氮罐取出冻存管，37℃水浴快速融化，离心洗涤后接种\",\"duration\":20},{\"stepNumber\":3,\"title\":\"细胞传代\",\"content\":\"胰蛋白酶消化，终止消化后离心，按比例接种新培养瓶\",\"duration\":30},{\"stepNumber\":4,\"title\":\"细胞计数\",\"content\":\"台盼蓝染色计数，计算活细胞浓度和存活率\",\"duration\":10},{\"stepNumber\":5,\"title\":\"接种培养\",\"content\":\"按所需密度接种，放入CO2培养箱培养\",\"duration\":15},{\"stepNumber\":6,\"title\":\"日常观察\",\"content\":\"每天显微镜观察细胞形态和密度，记录生长状态\",\"duration\":5},{\"stepNumber\":7,\"title\":\"换液\",\"content\":\"每2-3天更换一次培养基，保持细胞营养供应\",\"duration\":10}]', 15, 500, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (20, '实验流程', NULL, 'PCR扩增实验的操作流程是什么？', 'PCR扩增实验操作流程：\n1. 引物设计：根据目标基因序列设计特异性引物，Tm值55-65℃，长度18-25bp，避免二聚体和发夹结构\n2. 反应体系配制（冰上操作）：模板DNA 1-2μL（10-100ng）、上下游引物各1μL（10μM）、dNTP Mix 2μL（2.5mM each）、10×Buffer 5μL、Taq酶0.5μL（5U/μL）、ddH2O补至50μL\n3. 分装至PCR管：将混合液轻轻混匀，短暂离心，分装至0.2mL PCR管\n4. PCR程序设置：预变性95℃ 5min → 变性95℃ 30s → 退火55-65℃ 30s → 延伸72℃ 1min/kb → 循环30次 → 终延伸72℃ 10min → 4℃保存\n5. 琼脂糖凝胶电泳检测：配制1-2%琼脂糖凝胶，点样后80-120V电泳30-45分钟\n6. 凝胶成像：紫外凝胶成像系统观察条带大小和亮度\n7. 结果分析：比对Marker判断扩增片段大小，评估扩增效率和特异性', 'PCR,DNA扩增,引物设计,琼脂糖电泳,Taq酶,基因扩增,分子生物学', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"引物设计\",\"content\":\"根据目标基因序列设计特异性引物，Tm值55-65℃\",\"duration\":30},{\"stepNumber\":2,\"title\":\"反应体系配制\",\"content\":\"冰上操作，按顺序加入各组分，ddH2O补至50μL\",\"duration\":15},{\"stepNumber\":3,\"title\":\"分装至PCR管\",\"content\":\"混合液轻轻混匀，短暂离心，分装至0.2mL PCR管\",\"duration\":5},{\"stepNumber\":4,\"title\":\"PCR程序设置\",\"content\":\"预变性→变性→退火→延伸循环30次→终延伸\",\"duration\":120},{\"stepNumber\":5,\"title\":\"琼脂糖凝胶电泳\",\"content\":\"配制1-2%凝胶，80-120V电泳30-45分钟\",\"duration\":60},{\"stepNumber\":6,\"title\":\"凝胶成像\",\"content\":\"紫外凝胶成像系统观察条带\",\"duration\":10},{\"stepNumber\":7,\"title\":\"结果分析\",\"content\":\"比对Marker判断扩增片段大小和特异性\",\"duration\":15}]', 12, 501, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (21, '实验流程', NULL, '蛋白质提取与定量实验流程是什么？', '蛋白质提取与定量实验流程：\n1. 样品准备：收集细胞或组织样本，预冷PBS洗涤2-3次，离心收集沉淀\n2. 裂解：加入RIPA裂解液（含PMSF蛋白酶抑制剂），冰上裂解30分钟，每10分钟涡旋混匀一次\n3. 离心取上清：4℃ 12000rpm离心15分钟，小心吸取上清至新管，避免吸到沉淀\n4. BCA法蛋白定量：配制BCA工作液，制作BSA标准曲线（0-2000μg/mL），样品适当稀释后加入96孔板，37℃孵育30分钟\n5. 酶标仪检测：562nm波长读取吸光度，根据标准曲线计算蛋白浓度\n6. 蛋白保存：调整浓度后加入Loading Buffer，100℃煮沸5分钟变性，-20℃或-80℃保存备用\n7. 注意事项：全程冰上操作，避免反复冻融，蛋白酶抑制剂现用现加', '蛋白质提取,BCA定量,RIPA裂解液,蛋白定量,Western Blot,蛋白酶抑制剂', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"样品准备\",\"content\":\"收集细胞或组织，预冷PBS洗涤2-3次\",\"duration\":10},{\"stepNumber\":2,\"title\":\"裂解\",\"content\":\"加RIPA裂解液，冰上裂解30分钟，每10分钟涡旋\",\"duration\":35},{\"stepNumber\":3,\"title\":\"离心取上清\",\"content\":\"4℃ 12000rpm离心15分钟，吸取上清\",\"duration\":20},{\"stepNumber\":4,\"title\":\"BCA法蛋白定量\",\"content\":\"配制BCA工作液和BSA标准曲线，37℃孵育30分钟\",\"duration\":45},{\"stepNumber\":5,\"title\":\"酶标仪检测\",\"content\":\"562nm读取吸光度，计算蛋白浓度\",\"duration\":10},{\"stepNumber\":6,\"title\":\"蛋白保存\",\"content\":\"加Loading Buffer煮沸变性，-20℃保存\",\"duration\":15}]', 8, 502, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (22, '实验流程', NULL, '紫外分光光度法测定溶液浓度的实验流程？', '紫外分光光度法测定溶液浓度流程：\n1. 仪器预热：打开紫外可见分光光度计，预热30分钟使光源稳定\n2. 选择波长：根据待测物质的最大吸收波长设定检测波长（如核酸260nm，蛋白质280nm）\n3. 比色皿准备：使用配对的石英比色皿（紫外区）或玻璃比色皿（可见光区），用待测溶液润洗2-3次\n4. 空白调零：在参比池和样品池中放入空白溶剂，执行基线校正/调零操作\n5. 标准曲线制作：配制5-7个浓度梯度的标准溶液，分别测定吸光度，绘制A-C标准曲线\n6. 样品测定：将待测样品放入样品池，读取吸光度值，每个样品测定3次取平均值\n7. 结果计算：根据标准曲线方程计算样品浓度，注意稀释倍数的换算\n8. 数据处理：计算R²值验证线性关系（R²≥0.999），报告平均值和标准差', '分光光度法,吸光度,标准曲线,比色皿,浓度测定,紫外光谱,朗伯比尔定律', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"仪器预热\",\"content\":\"打开分光光度计预热30分钟\",\"duration\":30},{\"stepNumber\":2,\"title\":\"选择波长\",\"content\":\"根据待测物质最大吸收波长设定\",\"duration\":5},{\"stepNumber\":3,\"title\":\"比色皿准备\",\"content\":\"配对比色皿，用待测溶液润洗2-3次\",\"duration\":10},{\"stepNumber\":4,\"title\":\"空白调零\",\"content\":\"放入空白溶剂执行基线校正\",\"duration\":5},{\"stepNumber\":5,\"title\":\"标准曲线制作\",\"content\":\"测定5-7个浓度梯度标准溶液\",\"duration\":30},{\"stepNumber\":6,\"title\":\"样品测定\",\"content\":\"读取吸光度，每个样品测3次取平均\",\"duration\":15},{\"stepNumber\":7,\"title\":\"结果计算\",\"content\":\"根据标准曲线计算浓度，注意稀释倍数\",\"duration\":10}]', 10, 503, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (23, '实验流程', NULL, '高效液相色谱（HPLC）分析实验流程？', 'HPLC分析实验流程：\n1. 流动相准备：根据方法要求配制流动相，使用色谱纯试剂，0.45μm滤膜过滤，超声脱气15-20分钟\n2. 仪器开机与平衡：启动HPLC各模块，设置流速和柱温，用初始流动相平衡色谱柱30-60分钟至基线平稳\n3. 系统适用性测试：进标准品溶液，检查理论塔板数、分离度、拖尾因子是否符合要求\n4. 标准曲线制作：配制5-7个浓度梯度的标准品溶液，分别进样记录峰面积，绘制标准曲线\n5. 样品前处理：根据样品类型选择合适的前处理方法（稀释、萃取、过滤等），0.22μm滤膜过滤后进样\n6. 样品测定：设置进样体积和梯度洗脱程序，依次进样，记录色谱图和峰面积\n7. 数据分析：根据保留时间定性，根据峰面积和标准曲线定量，计算含量和RSD值', 'HPLC,液相色谱,流动相,色谱柱,标准曲线,梯度洗脱,峰面积,保留时间', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"流动相准备\",\"content\":\"配制流动相，0.45μm滤膜过滤，超声脱气\",\"duration\":30},{\"stepNumber\":2,\"title\":\"仪器平衡\",\"content\":\"启动HPLC，平衡色谱柱30-60分钟\",\"duration\":45},{\"stepNumber\":3,\"title\":\"系统适用性测试\",\"content\":\"进标准品检查塔板数、分离度、拖尾因子\",\"duration\":15},{\"stepNumber\":4,\"title\":\"标准曲线制作\",\"content\":\"5-7个浓度梯度标准品进样，绘制标准曲线\",\"duration\":60},{\"stepNumber\":5,\"title\":\"样品前处理\",\"content\":\"稀释、萃取、0.22μm过滤\",\"duration\":20},{\"stepNumber\":6,\"title\":\"样品测定\",\"content\":\"设置梯度洗脱程序，依次进样\",\"duration\":30},{\"stepNumber\":7,\"title\":\"数据分析\",\"content\":\"保留时间定性，峰面积定量，计算RSD\",\"duration\":20}]', 18, 504, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (24, '实验流程', NULL, '微生物接种与培养实验流程？', '微生物接种与培养实验流程：\n1. 培养基准备：根据实验需求选择合适培养基（液体/固体），高压蒸汽灭菌121℃ 20分钟\n2. 无菌操作准备：进入超净工作台/生物安全柜前，开启UV灯照射30分钟，关闭UV后开启风机运行10分钟，用75%酒精擦拭台面和双手\n3. 接种环灭菌：接种环在酒精灯火焰上灼烧至红热，冷却后使用\n4. 接种操作：平板划线法（分离单菌落）或液体接种法（增菌培养），操作时靠近火焰区域\n5. 培养：将接种后的培养基倒置放入恒温培养箱，细菌37℃培养18-24h，真菌28℃培养2-5天\n6. 观察记录：观察菌落形态（大小、形状、颜色、边缘特征），记录生长情况\n7. 纯化：挑取单菌落进行二次划线纯化，必要时进行革兰氏染色鉴定', '微生物,接种,培养,无菌操作,划线,菌落,培养基,灭菌', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"培养基准备\",\"content\":\"选择合适培养基，121℃高压灭菌20分钟\",\"duration\":30},{\"stepNumber\":2,\"title\":\"无菌操作准备\",\"content\":\"UV照射30分钟，75%酒精擦拭\",\"duration\":40},{\"stepNumber\":3,\"title\":\"接种环灭菌\",\"content\":\"火焰灼烧至红热，冷却后使用\",\"duration\":2},{\"stepNumber\":4,\"title\":\"接种操作\",\"content\":\"平板划线或液体接种，靠近火焰操作\",\"duration\":10},{\"stepNumber\":5,\"title\":\"培养\",\"content\":\"放入恒温培养箱，细菌37℃ 18-24h\",\"duration\":1440},{\"stepNumber\":6,\"title\":\"观察记录\",\"content\":\"观察菌落形态，记录生长情况\",\"duration\":15},{\"stepNumber\":7,\"title\":\"纯化鉴定\",\"content\":\"挑取单菌落二次划线，必要时染色鉴定\",\"duration\":30}]', 10, 505, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (25, '实验流程', NULL, '电子电路基础实验流程？', '电子电路基础实验流程：\n1. 实验预习：阅读实验指导书，理解电路原理，计算理论参数值，画出电路接线图\n2. 仪器准备：检查数字示波器、信号发生器、万用表和直流电源是否正常，校准探头\n3. 电路搭建：按照电路图在面包板/实验板上连接元器件，注意极性（电解电容、二极管等），检查接线无误\n4. 通电前检查：用万用表电阻档检查电源端对地是否短路，确认无短路后再通电\n5. 静态测量：通电后先测量各节点静态工作点（直流电压、电流），与理论值对比\n6. 动态测试：信号发生器输入测试信号，示波器观察输入输出波形，测量增益、频响等参数\n7. 数据记录与处理：记录测量数据，绘制波形图和特性曲线，分析误差原因\n8. 拆线整理：先关电源再拆线，元器件归位，整理实验台', '电路实验,示波器,信号发生器,万用表,面包板,电路搭建,电子测量', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"实验预习\",\"content\":\"阅读指导书，理解原理，计算理论值\",\"duration\":30},{\"stepNumber\":2,\"title\":\"仪器准备\",\"content\":\"检查示波器、信号源、万用表，校准探头\",\"duration\":15},{\"stepNumber\":3,\"title\":\"电路搭建\",\"content\":\"按电路图连接元器件，注意极性\",\"duration\":30},{\"stepNumber\":4,\"title\":\"通电前检查\",\"content\":\"万用表检查电源端对地是否短路\",\"duration\":5},{\"stepNumber\":5,\"title\":\"静态测量\",\"content\":\"测量各节点直流工作点\",\"duration\":20},{\"stepNumber\":6,\"title\":\"动态测试\",\"content\":\"输入信号，示波器观察波形，测量参数\",\"duration\":30},{\"stepNumber\":7,\"title\":\"数据记录\",\"content\":\"记录数据，绘制曲线，分析误差\",\"duration\":20},{\"stepNumber\":8,\"title\":\"拆线整理\",\"content\":\"先关电源再拆线，整理实验台\",\"duration\":10}]', 10, 506, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (26, '实验流程', NULL, '样品干燥与称量实验流程？', '样品干燥与称量实验流程：\n1. 干燥箱准备：检查电热恒温干燥箱是否清洁，设置所需温度（通常105-110℃），预热至设定温度稳定\n2. 称量瓶处理：将洁净称量瓶放入干燥箱，105℃烘1-2小时，取出放入干燥器中冷却至室温（约30分钟）\n3. 空瓶称量：在分析天平上准确称量干燥称量瓶质量（m1），精确至0.1mg，记录数据\n4. 样品称量：用减量法或直接称量法加入样品，记录称量瓶+样品质量（m2），样品质量=m2-m1\n5. 干燥处理：将含样品的称量瓶放入干燥箱，按标准要求干燥至恒重（通常2-4小时）\n6. 冷却称量：取出放入干燥器冷却30分钟，称量（m3），再次干燥1小时冷却称量，两次差值≤0.3mg即为恒重\n7. 结果计算：水分含量=(m2-m3)/(m2-m1)×100%，记录平行实验数据', '干燥,称量,分析天平,恒重,减量法,水分测定,称量瓶,干燥器', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"干燥箱准备\",\"content\":\"设置温度105-110℃，预热至稳定\",\"duration\":20},{\"stepNumber\":2,\"title\":\"称量瓶处理\",\"content\":\"洁净称量瓶105℃烘1-2小时，干燥器冷却\",\"duration\":90},{\"stepNumber\":3,\"title\":\"空瓶称量\",\"content\":\"分析天平称量，精确至0.1mg\",\"duration\":5},{\"stepNumber\":4,\"title\":\"样品称量\",\"content\":\"减量法或直接称量法加入样品\",\"duration\":10},{\"stepNumber\":5,\"title\":\"干燥处理\",\"content\":\"放入干燥箱干燥至恒重\",\"duration\":180},{\"stepNumber\":6,\"title\":\"冷却称量\",\"content\":\"干燥器冷却30分钟后称量至恒重\",\"duration\":40},{\"stepNumber\":7,\"title\":\"结果计算\",\"content\":\"计算水分含量，记录平行实验数据\",\"duration\":10}]', 8, 507, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (27, '故障排查', NULL, '离心机运行时异常振动怎么办？', '离心机异常振动排查步骤：\n1. 立即停止运行：按下停止键，不要强行开盖，等待转子完全停止\n2. 检查样品平衡：确认对称位置的离心管重量是否相等（差异应<0.1g），溶液体积是否一致\n3. 检查转子安装：确认转子是否安装到位，转子盖是否拧紧，转子与轴的配合面是否清洁\n4. 检查离心管：确认离心管是否有裂纹或变形，管盖是否密封，管内是否有气泡\n5. 检查水平：用水平仪检查离心机是否放置在水平台面上，调整底脚螺丝\n6. 检查减震系统：查看减震垫是否老化或损坏，必要时更换\n7. 重新运行：确认以上问题排除后，从低速开始逐步升速，观察是否仍有振动\n\n⚠️ 严重振动时禁止继续运行，可能导致转子飞出造成人身伤害！', '离心机,振动,不平衡,转子,故障,排查,安全', 1, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"立即停机\",\"content\":\"按下停止键，等待转子完全停止\",\"duration\":2},{\"stepNumber\":2,\"title\":\"检查样品平衡\",\"content\":\"确认对称位置离心管重量相等\",\"duration\":5},{\"stepNumber\":3,\"title\":\"检查转子安装\",\"content\":\"确认转子安装到位，盖拧紧\",\"duration\":5},{\"stepNumber\":4,\"title\":\"检查离心管\",\"content\":\"确认无裂纹变形，管盖密封\",\"duration\":3},{\"stepNumber\":5,\"title\":\"检查水平\",\"content\":\"用水平仪检查，调整底脚螺丝\",\"duration\":5},{\"stepNumber\":6,\"title\":\"检查减震系统\",\"content\":\"查看减震垫是否老化损坏\",\"duration\":5},{\"stepNumber\":7,\"title\":\"重新运行\",\"content\":\"从低速逐步升速观察\",\"duration\":10}]', 12, 600, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (28, '故障排查', NULL, '显微镜成像模糊怎么排查？', '显微镜成像模糊排查步骤：\n1. 检查物镜：确认物镜是否正确旋入转盘并卡位，物镜前透镜是否清洁（用擦镜纸蘸无水乙醇轻擦）\n2. 检查样品：确认盖玻片朝上放置，样品切片是否过厚（应<10μm），封片剂是否均匀无气泡\n3. 调焦操作：先用低倍物镜粗调找到大致焦面，再转换高倍物镜微调，注意勿压碎盖玻片\n4. 检查聚光镜：调节聚光镜高度和孔径光阑，柯勒照明是否正确设置\n5. 检查目镜：目镜镜片是否清洁，屈光度是否调节正确（双眼分别调节至十字线清晰）\n6. 检查光源：卤素灯亮度是否足够，LED光源是否正常，滤光片是否正确放置\n7. 检查相机：如使用数码摄像头，检查接口是否松动，软件设置是否正确\n8. 环境因素：检查工作台是否稳定，有无振动源干扰', '显微镜,模糊,调焦,物镜,成像,清洁,故障排查', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"检查物镜\",\"content\":\"确认物镜卡位正确，前透镜清洁\",\"duration\":3},{\"stepNumber\":2,\"title\":\"检查样品\",\"content\":\"盖玻片朝上，切片厚度<10μm\",\"duration\":2},{\"stepNumber\":3,\"title\":\"调焦操作\",\"content\":\"低倍粗调→高倍微调\",\"duration\":5},{\"stepNumber\":4,\"title\":\"检查聚光镜\",\"content\":\"调节聚光镜高度和孔径光阑\",\"duration\":5},{\"stepNumber\":5,\"title\":\"检查目镜\",\"content\":\"清洁目镜，调节屈光度\",\"duration\":3},{\"stepNumber\":6,\"title\":\"检查光源\",\"content\":\"确认光源亮度和滤光片\",\"duration\":3},{\"stepNumber\":7,\"title\":\"检查相机\",\"content\":\"接口和软件设置\",\"duration\":5}]', 10, 601, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (29, '故障排查', NULL, 'CO2培养箱温度或CO2浓度异常怎么处理？', 'CO2培养箱异常排查步骤：\n1. 温度异常：\n   - 检查温度设定值是否正确（通常37℃）\n   - 检查门密封条是否完好，关门是否严密\n   - 检查水盘水位是否正常（维持箱内湿度）\n   - 检查周围环境温度是否过高或通风不良\n   - 用独立温度计校验显示温度是否准确\n2. CO2浓度异常：\n   - 检查CO2气瓶是否有气（压力表读数），减压阀输出压力是否为0.05-0.1MPa\n   - 检查CO2气管路连接是否漏气（用肥皂水检测接口）\n   - 检查红外CO2传感器是否需要校准（建议每6个月校准一次）\n   - 检查HEPA过滤器是否堵塞需要更换\n3. 通用措施：重启培养箱，让系统自检和重新校准；如仍异常，联系设备维护人员', 'CO2培养箱,温度异常,CO2浓度,气瓶,传感器,校准,故障排查', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"检查温度设定\",\"content\":\"确认设定值37℃，门密封完好\",\"duration\":5},{\"stepNumber\":2,\"title\":\"检查水盘水位\",\"content\":\"确认水盘水位正常维持湿度\",\"duration\":3},{\"stepNumber\":3,\"title\":\"检查环境\",\"content\":\"周围环境温度和通风情况\",\"duration\":5},{\"stepNumber\":4,\"title\":\"检查CO2气瓶\",\"content\":\"气瓶压力，减压阀输出0.05-0.1MPa\",\"duration\":5},{\"stepNumber\":5,\"title\":\"检查气路密封\",\"content\":\"肥皂水检测接口是否漏气\",\"duration\":10},{\"stepNumber\":6,\"title\":\"传感器校准\",\"content\":\"红外CO2传感器每6个月校准一次\",\"duration\":30},{\"stepNumber\":7,\"title\":\"重启自检\",\"content\":\"重启培养箱，系统自检和重新校准\",\"duration\":15}]', 8, 602, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (30, '故障排查', NULL, 'HPLC基线漂移或噪声过大怎么处理？', 'HPLC基线问题排查步骤：\n1. 基线漂移：\n   - 检查流动相是否充分脱气（重新超声脱气15-20分钟）\n   - 检查柱温是否稳定（柱温波动会导致基线漂移）\n   - 检查流动相比例是否变化（梯度洗脱时属正常现象）\n   - 检查检测器流通池是否有气泡（用流动相冲洗排气）\n   - 检查色谱柱是否污染（用强溶剂冲洗再生）\n2. 基线噪声过大：\n   - 检查检测器灯源是否老化（氘灯寿命约2000小时，需更换）\n   - 检查流动相纯度（使用色谱纯试剂）\n   - 检查系统是否有漏液（检查各接头）\n   - 检查泵脉动（是否需要更换密封圈）\n   - 检查电气干扰（确保仪器良好接地）\n3. 预防措施：定期维护检测器，更换在线过滤器，使用保护柱', 'HPLC,基线漂移,噪声,脱气,检测器,色谱柱,故障排查,液相色谱', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"检查流动相脱气\",\"content\":\"重新超声脱气15-20分钟\",\"duration\":25},{\"stepNumber\":2,\"title\":\"检查柱温\",\"content\":\"确认柱温箱温度稳定\",\"duration\":5},{\"stepNumber\":3,\"title\":\"检查流通池气泡\",\"content\":\"用流动相冲洗排气\",\"duration\":10},{\"stepNumber\":4,\"title\":\"检查检测器灯源\",\"content\":\"氘灯寿命约2000小时，老化需更换\",\"duration\":10},{\"stepNumber\":5,\"title\":\"检查流动相纯度\",\"content\":\"使用色谱纯试剂和超纯水\",\"duration\":5},{\"stepNumber\":6,\"title\":\"检查系统漏液\",\"content\":\"检查各接头和管路\",\"duration\":10},{\"stepNumber\":7,\"title\":\"检查电气干扰\",\"content\":\"确保仪器良好接地\",\"duration\":5}]', 12, 603, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (31, '故障排查', NULL, '分析天平读数不稳定怎么排查？', '分析天平读数不稳定排查步骤：\n1. 环境因素：\n   - 检查天平是否放在防震台上，远离空调出风口和门窗\n   - 检查室内温度是否剧烈变化（温差<2℃/小时）\n   - 检查室内湿度是否合适（相对湿度45-60%）\n2. 操作因素：\n   - 确认天平预热时间充足（至少30分钟）\n   - 确认称量容器温度与天平室一致（烘干的器皿需冷却后称量）\n   - 确认称量时关闭天平门，避免气流影响\n   - 避免手直接接触称量器皿（使用手套或镊子）\n3. 仪器因素：\n   - 执行校准操作（内校或外校砝码校准）\n   - 检查称量盘是否清洁，有无异物\n   - 检查防风罩是否完好\n4. 静电干扰：干燥季节易产生静电，使用静电消除器或增加室内湿度', '天平,读数不稳定,校准,防震,静电,称量,故障排查', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"检查环境\",\"content\":\"防震台、远离空调、温湿度适宜\",\"duration\":10},{\"stepNumber\":2,\"title\":\"检查预热\",\"content\":\"预热至少30分钟\",\"duration\":30},{\"stepNumber\":3,\"title\":\"检查操作\",\"content\":\"关门称量，戴手套，器皿恒温\",\"duration\":5},{\"stepNumber\":4,\"title\":\"执行校准\",\"content\":\"内校或外校砝码校准\",\"duration\":10},{\"stepNumber\":5,\"title\":\"检查称量盘\",\"content\":\"清洁称量盘和防风罩\",\"duration\":5},{\"stepNumber\":6,\"title\":\"消除静电\",\"content\":\"使用静电消除器或增加湿度\",\"duration\":5}]', 8, 604, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (32, '故障排查', NULL, 'PCR扩增没有条带或条带弱怎么排查？', 'PCR扩增失败排查步骤：\n1. 无条带：\n   - 检查模板DNA质量（跑凝胶看是否降解，OD260/280应在1.8-2.0）\n   - 检查引物是否正确（序列、方向、浓度），重新设计或更换引物\n   - 优化退火温度（梯度PCR测试54-68℃范围）\n   - 检查Taq酶活性（阳性对照验证）\n   - 检查dNTP和Buffer是否过期\n2. 条带弱：\n   - 增加模板量（10-100ng→100-500ng）\n   - 增加循环数（30→35，但不超过40）\n   - 降低退火温度（降低2-5℃）\n   - 延长延伸时间（1min/kb→1.5min/kb）\n3. 非特异性条带：\n   - 提高退火温度\n   - 减少模板量\n   - 使用热启动Taq酶\n   - 优化Mg²⁺浓度（1.5-3.0mM）', 'PCR,无条带,扩增失败,引物,退火温度,Taq酶,模板DNA,非特异性', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"检查模板质量\",\"content\":\"凝胶检查DNA完整性，OD260/280=1.8-2.0\",\"duration\":15},{\"stepNumber\":2,\"title\":\"检查引物\",\"content\":\"确认序列方向浓度正确\",\"duration\":10},{\"stepNumber\":3,\"title\":\"优化退火温度\",\"content\":\"梯度PCR测试54-68℃\",\"duration\":120},{\"stepNumber\":4,\"title\":\"验证酶活性\",\"content\":\"阳性对照验证Taq酶\",\"duration\":120},{\"stepNumber\":5,\"title\":\"调整循环数\",\"content\":\"增加至35循环，不超过40\",\"duration\":5},{\"stepNumber\":6,\"title\":\"优化Mg²⁺浓度\",\"content\":\"测试1.5-3.0mM范围\",\"duration\":120}]', 10, 605, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (33, '故障排查', NULL, '干燥箱温度达不到设定值怎么办？', '干燥箱温度异常排查步骤：\n1. 检查设定值：确认温度设定值是否正确，是否超出设备量程范围\n2. 检查加热元件：\n   - 用万用表测量加热丝电阻，判断是否断路\n   - 检查固态继电器（SSR）是否正常工作\n3. 检查传感器：\n   - PT100温度传感器是否准确（用标准温度计对比）\n   - 传感器接线是否松动或氧化\n4. 检查密封性：箱门密封条是否老化变形，关门后有无缝隙漏热\n5. 检查通风：排气孔是否被堵塞，鼓风机是否正常运转\n6. 检查PID参数：温度控制器PID参数是否需要重新自整定\n7. 环境因素：环境温度过低或通风散热不良可能影响升温速度', '干燥箱,温度异常,加热元件,传感器,PID,密封,故障排查', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"检查设定值\",\"content\":\"确认温度设定正确，未超量程\",\"duration\":2},{\"stepNumber\":2,\"title\":\"检查加热元件\",\"content\":\"万用表测加热丝电阻，检查SSR\",\"duration\":15},{\"stepNumber\":3,\"title\":\"检查传感器\",\"content\":\"PT100对比标准温度计\",\"duration\":10},{\"stepNumber\":4,\"title\":\"检查密封性\",\"content\":\"密封条是否老化，有无漏热\",\"duration\":5},{\"stepNumber\":5,\"title\":\"检查通风\",\"content\":\"排气孔和鼓风机是否正常\",\"duration\":5},{\"stepNumber\":6,\"title\":\"PID自整定\",\"content\":\"温度控制器PID参数重新自整定\",\"duration\":30}]', 6, 606, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (34, '故障排查', NULL, '示波器无法显示波形怎么排查？', '示波器无波形显示排查步骤：\n1. 检查信号连接：确认探头BNC接头是否插紧，探头接地夹是否连接到电路地\n2. 检查探头补偿：探头补偿电容是否调节正确（方波顶部平直无过冲/欠冲）\n3. 检查通道设置：\n   - 确认通道是否打开（CH1/CH2按钮亮起）\n   - 检查垂直刻度（V/div）是否设置过大导致波形太小看不见\n   - 检查水平刻度（S/div）是否设置不当\n   - 检查触发电平是否在信号范围内\n4. 按Auto键：让示波器自动设置参数，确认信号是否正常\n5. 检查耦合方式：确认不是设置在GND耦合模式（应设为DC或AC）\n6. 检查信号源：用万用表确认被测点确实有信号输出\n7. 检查探头：更换已知好的探头测试，排除探头损坏', '示波器,无波形,探头,触发,通道,补偿,故障排查', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"检查信号连接\",\"content\":\"BNC接头插紧，接地夹连接\",\"duration\":3},{\"stepNumber\":2,\"title\":\"检查探头补偿\",\"content\":\"调节补偿电容，方波顶部平直\",\"duration\":5},{\"stepNumber\":3,\"title\":\"检查通道设置\",\"content\":\"通道打开，V/div和S/div适当\",\"duration\":5},{\"stepNumber\":4,\"title\":\"按Auto键\",\"content\":\"自动设置参数确认信号\",\"duration\":3},{\"stepNumber\":5,\"title\":\"检查耦合方式\",\"content\":\"确认不是GND模式\",\"duration\":2},{\"stepNumber\":6,\"title\":\"检查信号源\",\"content\":\"万用表确认被测点有信号\",\"duration\":5},{\"stepNumber\":7,\"title\":\"更换探头\",\"content\":\"排除探头损坏\",\"duration\":5}]', 8, 607, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (35, '故障排查', NULL, '设备漏电怎么处理？', '⚠️ 安全警告：设备漏电属于紧急危险情况！\n\n漏电处理步骤：\n1. 立即断电：不要触碰设备金属外壳！先断开电源插头或拉下空气开关\n2. 人员安全：如有人触电，切勿直接拉拽！用干燥木棒或绝缘物将人与电源分离，拨打120急救\n3. 标识警示：在设备上张贴\"漏电危险 禁止使用\"标识，通知实验室管理人员\n4. 排查原因：\n   - 检查电源线绝缘层是否破损老化\n   - 检查设备内部是否有液体泼洒导致短路\n   - 检查接地线是否断开或接触不良\n   - 检查插头插座是否进水或氧化\n5. 绝缘测试：用兆欧表（绝缘电阻测试仪）测量设备绝缘电阻，应≥2MΩ\n6. 维修确认：由专业维修人员修复后，再次测量绝缘电阻合格方可重新使用\n\n⚠️ 严禁带电操作！严禁用水灭火！严禁私自拆修！', '漏电,触电,安全,断电,绝缘,接地,紧急,危险', 1, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"立即断电\",\"content\":\"不要触碰设备！断开电源插头或空气开关\",\"duration\":1},{\"stepNumber\":2,\"title\":\"人员安全\",\"content\":\"用绝缘物分离触电者，拨打120\",\"duration\":2},{\"stepNumber\":3,\"title\":\"标识警示\",\"content\":\"张贴危险标识，通知管理人员\",\"duration\":3},{\"stepNumber\":4,\"title\":\"排查原因\",\"content\":\"检查电源线、液体泼洒、接地线\",\"duration\":15},{\"stepNumber\":5,\"title\":\"绝缘测试\",\"content\":\"兆欧表测量绝缘电阻≥2MΩ\",\"duration\":10},{\"stepNumber\":6,\"title\":\"维修确认\",\"content\":\"专业维修后复测合格方可使用\",\"duration\":60}]', 15, 608, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (36, '故障排查', NULL, '分光光度计读数异常怎么排查？', '分光光度计读数异常排查步骤：\n1. 无法调零/调百：\n   - 检查光源灯是否点亮（可见光钨灯/紫外氘灯），灯丝是否老化发黑\n   - 检查比色皿是否配对（同一批次石英/玻璃比色皿）\n   - 检查比色皿是否清洁无指纹和残留液\n   - 检查样品室盖是否关紧，有无漏光\n2. 读数不稳定：\n   - 检查电源电压是否稳定（建议使用稳压电源）\n   - 检查环境是否有强振动源\n   - 检查比色皿中是否有气泡\n   - 预热时间是否充足（至少30分钟）\n3. 线性不好：\n   - 检查浓度范围是否在朗伯-比尔定律线性范围内\n   - 检查比色皿光程是否准确\n   - 检查狭缝宽度设置是否合适\n4. 波长不准：用镨钕滤光片或汞灯特征峰校验波长精度', '分光光度计,读数异常,调零,光源,比色皿,波长校准,故障排查', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"检查光源\",\"content\":\"灯是否点亮，灯丝是否老化\",\"duration\":5},{\"stepNumber\":2,\"title\":\"检查比色皿\",\"content\":\"配对比色皿，清洁无指纹\",\"duration\":5},{\"stepNumber\":3,\"title\":\"检查样品室\",\"content\":\"盖是否关紧，有无漏光\",\"duration\":3},{\"stepNumber\":4,\"title\":\"检查电源环境\",\"content\":\"电压稳定，无振动源\",\"duration\":5},{\"stepNumber\":5,\"title\":\"检查预热\",\"content\":\"预热至少30分钟\",\"duration\":30},{\"stepNumber\":6,\"title\":\"波长校验\",\"content\":\"用镨钕滤光片校验波长精度\",\"duration\":15}]', 8, 609, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (37, '安全规范', NULL, '实验室通用安全规范有哪些？', '实验室通用安全规范：\n1. 个人防护：进入实验室必须穿实验服、佩戴护目镜；长发须扎起；禁止穿拖鞋凉鞋；禁止佩戴隐形眼镜（化学品溅入时更危险）\n2. 化学品安全：\n   - 使用前阅读SDS（安全数据表），了解化学品危害和应急措施\n   - 易挥发、有毒化学品必须在通风橱内操作\n   - 严禁口吸移液管，必须使用洗耳球或移液器\n   - 化学品按相容性分类存放，酸碱分开，氧化剂与还原剂分开\n3. 电气安全：\n   - 湿手不触碰电器开关和插头\n   - 不私拉乱接电线，不超负荷使用插座\n   - 大功率设备使用独立回路和接地保护\n4. 紧急处理：\n   - 熟悉实验室紧急出口、灭火器、洗眼器、紧急喷淋位置\n   - 化学品溅入眼睛立即用洗眼器冲洗15分钟\n   - 发生火灾先报警再灭火，小火用灭火器，大火立即撤离\n5. 废弃物处理：分类收集，含重金属废液、有机废液、生物废料分别收集处理', '安全规范,实验室安全,个人防护,化学品,电气安全,紧急处理,废弃物', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"个人防护\",\"content\":\"实验服、护目镜、扎发、禁止拖鞋\"},{\"stepNumber\":2,\"title\":\"化学品安全\",\"content\":\"阅读SDS，通风橱操作，分类存放\"},{\"stepNumber\":3,\"title\":\"电气安全\",\"content\":\"湿手不触电，不私拉电线，接地保护\"},{\"stepNumber\":4,\"title\":\"紧急处理\",\"content\":\"熟悉安全设施位置，化学品溅眼冲洗15分钟\"},{\"stepNumber\":5,\"title\":\"废弃物处理\",\"content\":\"分类收集，分别处理\"}]', 20, 700, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (38, '安全规范', NULL, '化学品泄漏的应急处理流程？', '⚠️ 化学品泄漏应急处理流程：\n1. 评估危险：判断泄漏化学品种类、数量和危险程度，小量泄漏可自行处理，大量或有毒泄漏立即撤离并报警\n2. 个人防护：处理泄漏前必须佩戴适当PPE（防化手套、护目镜、防护面罩、防化服）\n3. 控制泄漏源：关闭阀门、扶正倒伏容器、用吸附棉围堵防止扩散\n4. 酸类泄漏：用沙土或碳酸氢钠覆盖中和，收集后作为危险废物处理\n5. 碱类泄漏：用沙土覆盖，用稀醋酸中和后收集处理\n6. 有机溶剂泄漏：用吸附棉或蛭石吸附，避免明火（多数有机溶剂易燃），收集至密封容器\n7. 通风处理：打开通风系统和窗户，人员撤离至安全区域等待空气置换\n8. 报告记录：填写事故报告，记录泄漏化学品、时间、处理措施和人员暴露情况\n\n⚠️ 不确定如何处理时，立即撤离并拨打校园报警电话！', '化学品泄漏,应急,酸碱,有机溶剂,吸附,中和,危险,安全', 1, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"评估危险\",\"content\":\"判断化学品种类和危险程度\"},{\"stepNumber\":2,\"title\":\"个人防护\",\"content\":\"佩戴防化手套、护目镜、面罩\"},{\"stepNumber\":3,\"title\":\"控制泄漏源\",\"content\":\"关闭阀门，围堵防止扩散\"},{\"stepNumber\":4,\"title\":\"酸类处理\",\"content\":\"碳酸氢钠覆盖中和\"},{\"stepNumber\":5,\"title\":\"碱类处理\",\"content\":\"稀醋酸中和后收集\"},{\"stepNumber\":6,\"title\":\"有机溶剂处理\",\"content\":\"吸附棉吸附，避免明火\"},{\"stepNumber\":7,\"title\":\"通风处理\",\"content\":\"打开通风系统，人员撤离\"},{\"stepNumber\":8,\"title\":\"报告记录\",\"content\":\"填写事故报告\"}]', 15, 701, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (39, '安全规范', NULL, '高压灭菌锅的安全操作规范？', '⚠️ 高压灭菌锅安全操作规范：\n1. 操作前检查：\n   - 检查安全阀是否灵活，压力表是否在零位\n   - 检查密封圈是否完好，锅门关闭是否严密\n   - 确认锅内加水至规定水位线\n2. 装载规范：\n   - 物品不要堆放过密，留出蒸汽流通空间\n   - 液体容器装量不超过2/3，瓶口不要密封（用棉塞或松盖）\n   - 禁止灭菌易燃易爆物品和腐蚀性化学品\n3. 操作流程：\n   - 关门确认密封→设定温度121℃和时间20min→启动加热→排冷气→升压→灭菌→自然冷却降压→压力归零后开盖\n4. ⚠️ 严禁事项：\n   - 严禁在压力未归零时强行开盖（可能导致爆炸！）\n   - 严禁超温超压运行\n   - 严禁无人值守运行\n   - 严禁私自改装安全阀\n5. 维护保养：每周检查密封圈，每月检查安全阀，每年校验压力表', '高压灭菌锅,灭菌,安全操作,压力,安全阀,121℃,危险', 1, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"操作前检查\",\"content\":\"安全阀、压力表、密封圈、水位\"},{\"stepNumber\":2,\"title\":\"装载规范\",\"content\":\"留蒸汽空间，液体不超2/3，松盖\"},{\"stepNumber\":3,\"title\":\"操作流程\",\"content\":\"关门→设定→排冷气→升压→灭菌→冷却→开盖\"},{\"stepNumber\":4,\"title\":\"严禁事项\",\"content\":\"压力未归零禁开盖！禁超温超压！禁无人值守！\"},{\"stepNumber\":5,\"title\":\"维护保养\",\"content\":\"每周密封圈，每月安全阀，每年压力表\"}]', 12, 702, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (40, '安全规范', NULL, '离心机安全操作规范有哪些？', '⚠️ 离心机安全操作规范：\n1. 使用前检查：确认转子无裂纹、无腐蚀，离心管完好无损\n2. 严格配平：对称位置的离心管重量必须相等（差异<0.1g），液体体积一致\n3. 选择合适转子：根据转速和样品量选择合适转子，不超过转子最大转速\n4. 超速离心机必须使用专用离心管，普通离心管在高速下可能破裂\n5. 运行中：\n   - 盖紧转子盖和机盖\n   - 从低速逐步升速，观察有无异常振动\n   - 有异常振动或异响立即停止\n   - 运行中不得强行开盖\n6. 使用后：\n   - 等待转子完全停止再开盖\n   - 取出离心管后清洁转子，擦干水分\n   - 转子定期检查和更换（按厂家建议的使用寿命）\n7. ⚠️ 危险操作警告：\n   - 禁止不平衡运行！可能导致转子飞出\n   - 禁止超速运行！可能导致转子破裂\n   - 禁止在转子未停止时开盖！', '离心机,安全操作,配平,转子,平衡,超速,危险', 1, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"使用前检查\",\"content\":\"转子无裂纹，离心管完好\"},{\"stepNumber\":2,\"title\":\"严格配平\",\"content\":\"对称位置重量差<0.1g\"},{\"stepNumber\":3,\"title\":\"选择转子\",\"content\":\"合适转速和样品量，不超最大转速\"},{\"stepNumber\":4,\"title\":\"运行监控\",\"content\":\"盖紧盖子，逐步升速，异常即停\"},{\"stepNumber\":5,\"title\":\"使用后\",\"content\":\"等待停止再开盖，清洁擦干转子\"},{\"stepNumber\":6,\"title\":\"危险警告\",\"content\":\"禁不平衡！禁超速！禁未停开盖！\"}]', 12, 703, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (41, '安全规范', NULL, '实验室火灾应急处理流程？', '⚠️ 实验室火灾应急处理流程：\n1. 发现火情：大声呼喊\"着火了\"，按下火灾报警按钮，拨打119报警\n2. 初期灭火（火势较小时）：\n   - 电器火灾：先断电！用CO2灭火器或干粉灭火器，严禁用水！\n   - 油类火灾：用泡沫灭火器或沙土覆盖，严禁用水！\n   - 一般火灾：用干粉灭火器或水基灭火器\n3. 灭火器使用方法（PASS法则）：\n   - P(Pull)：拔出保险销\n   - A(Aim)：对准火焰根部\n   - S(Squeeze)：压下压把\n   - S(Sweep)：左右扫射\n4. 无法控制时：\n   - 立即撤离！关闭房门阻止火势蔓延\n   - 用湿毛巾捂住口鼻，低姿沿安全通道撤离\n   - 不乘坐电梯，不返回取物\n5. 集合点名：到达安全集合点后清点人数，报告失踪人员\n6. 协助救援：向消防人员提供实验室化学品存放信息和建筑布局', '火灾,灭火器,应急,撤离,报警,电器火灾,油类火灾,安全', 1, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"发现火情\",\"content\":\"大声呼喊，按报警器，拨打119\"},{\"stepNumber\":2,\"title\":\"初期灭火\",\"content\":\"电器断电用CO2，油类用泡沫，严禁用水\"},{\"stepNumber\":3,\"title\":\"灭火器使用\",\"content\":\"PASS法则：拔销→瞄准→压把→扫射\"},{\"stepNumber\":4,\"title\":\"紧急撤离\",\"content\":\"湿毛巾捂口鼻，低姿沿通道撤离\"},{\"stepNumber\":5,\"title\":\"集合点名\",\"content\":\"安全点清点人数，报告失踪人员\"},{\"stepNumber\":6,\"title\":\"协助救援\",\"content\":\"提供化学品信息和建筑布局\"}]', 18, 704, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (42, '安全规范', NULL, '有毒化学品的安全使用规范？', '⚠️ 有毒化学品安全使用规范：\n1. 使用前准备：\n   - 阅读SDS了解毒性、暴露限值和急救措施\n   - 在通风橱内操作，确保面风速0.4-0.6m/s\n   - 佩戴适当PPE：防化手套（丁腈/氯丁橡胶）、护目镜、防护面罩\n2. 剧毒化学品（如氰化物、汞化合物）：\n   - 双人双锁管理，使用需审批登记\n   - 操作时必须有第二人在场监护\n   - 备有专用解毒剂（如氰化物备亚硝酸异戊酯）\n3. 操作规范：\n   - 严禁口吸移液，使用移液器或注射器\n   - 称量时使用密闭容器或手套箱\n   - 操作完毕立即洗手，脱下手套后再次洗手\n4. 应急处理：\n   - 皮肤接触：立即脱去污染衣物，大量清水冲洗15分钟以上\n   - 吸入：转移至空气新鲜处，如呼吸困难立即就医\n   - 误食：不要催吐（腐蚀性化学品），立即就医并携带SDS\n5. 废弃处理：含毒废液单独收集，交由有资质的危废处理单位处置', '有毒化学品,安全,通风橱,SDS,剧毒,防护,解毒,应急', 1, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"使用前准备\",\"content\":\"阅读SDS，通风橱操作，佩戴PPE\"},{\"stepNumber\":2,\"title\":\"剧毒管理\",\"content\":\"双人双锁，操作时监护人在场\"},{\"stepNumber\":3,\"title\":\"操作规范\",\"content\":\"禁口吸，密闭称量，操作后洗手\"},{\"stepNumber\":4,\"title\":\"应急-皮肤接触\",\"content\":\"脱去衣物，清水冲洗15分钟\"},{\"stepNumber\":5,\"title\":\"应急-吸入\",\"content\":\"转移至新鲜空气处，呼吸困难就医\"},{\"stepNumber\":6,\"title\":\"废弃处理\",\"content\":\"单独收集，交危废处理单位\"}]', 12, 705, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (43, '安全规范', NULL, '生物安全实验室操作规范？', '生物安全实验室操作规范：\n1. 进入要求：穿专用实验服、戴手套、护目镜；长发扎起；禁止穿露趾鞋；个人物品不得带入实验区\n2. 生物安全柜使用：\n   - 开机运行5分钟后方可操作\n   - 工作面风速0.36-0.54m/s\n   - 前窗开启高度不超过安全线（通常18-20cm）\n   - 柜内物品摆放不超过总面积的50%\n   - 操作区域在安全柜内至少10cm处\n3. 微生物操作规范：\n   - 所有操作尽量在生物安全柜内完成\n   - 减少气溶胶产生（避免剧烈振荡、快速移液）\n   - 污染的器具和材料需高压灭菌后再清洗或丢弃\n4. 意外暴露处理：\n   - 针刺伤：立即挤血、冲洗、消毒，报告并就医\n   - 溢洒：覆盖消毒纸巾，倾倒消毒液（含氯消毒液），30分钟后清理\n5. 废弃物处理：\n   - 锐器放入专用锐器盒\n   - 生物废料高压灭菌后按医疗废物处理\n   - 实验服单独清洗，不与日常衣物混洗', '生物安全,安全柜,微生物,气溶胶,针刺伤,消毒,废弃物', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"进入要求\",\"content\":\"实验服、手套、护目镜，禁止露趾鞋\"},{\"stepNumber\":2,\"title\":\"安全柜使用\",\"content\":\"运行5分钟后操作，前窗不超过安全线\"},{\"stepNumber\":3,\"title\":\"微生物操作\",\"content\":\"安全柜内操作，减少气溶胶产生\"},{\"stepNumber\":4,\"title\":\"意外暴露\",\"content\":\"针刺伤挤血冲洗消毒，溢洒消毒液覆盖\"},{\"stepNumber\":5,\"title\":\"废弃物处理\",\"content\":\"锐器盒、高压灭菌、实验服单独清洗\"}]', 10, 706, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (44, '安全规范', NULL, '放射性实验的安全防护规范？', '⚠️ 放射性实验安全防护规范：\n1. 基本原则：时间防护（缩短接触时间）、距离防护（增大与源的距离）、屏蔽防护（使用铅板/铅玻璃）\n2. 进入要求：\n   - 佩戴个人剂量计，定期读取记录\n   - 穿专用防护服，戴防护手套和防护眼镜\n   - 在指定区域操作，禁止在放射区饮食、化妆\n3. 操作规范：\n   - 使用长柄工具操作放射源，避免直接接触\n   - 操作前检查工作区域是否有污染（用表面污染仪检测）\n   - 操作后进行全身污染检测\n4. 应急处理：\n   - 放射源泄漏：立即撤离，封锁区域，通知辐射安全负责人\n   - 人员污染：脱去污染衣物，用大量清水冲洗，不要擦伤皮肤\n5. 废弃处理：放射性废物按半衰期分类收集，由专业机构回收处理', '放射性,辐射防护,剂量计,屏蔽,铅板,污染检测,应急', 1, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"防护原则\",\"content\":\"时间、距离、屏蔽三大防护原则\"},{\"stepNumber\":2,\"title\":\"进入要求\",\"content\":\"佩戴剂量计，穿防护服，禁止饮食\"},{\"stepNumber\":3,\"title\":\"操作规范\",\"content\":\"长柄工具，操作前后污染检测\"},{\"stepNumber\":4,\"title\":\"应急-泄漏\",\"content\":\"立即撤离，封锁区域，通知负责人\"},{\"stepNumber\":5,\"title\":\"应急-人员污染\",\"content\":\"脱去衣物，大量清水冲洗\"},{\"stepNumber\":6,\"title\":\"废弃处理\",\"content\":\"按半衰期分类，专业机构回收\"}]', 8, 707, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (45, '安全规范', NULL, '实验室紧急洗眼器和喷淋装置使用规范？', '紧急洗眼器和喷淋装置使用规范：\n1. 位置要求：安装在实验室出口附近，到达时间不超过10秒步行距离，通道无障碍物\n2. 洗眼器使用：\n   - 化学品溅入眼睛时立即使用\n   - 推开洗眼器盖板，水自动流出\n   - 用手撑开眼睑，眼球转动，冲洗至少15分钟\n   - 冲洗时避免污染水流到另一只眼\n   - 冲洗后立即就医，携带化学品SDS\n3. 紧急喷淋使用：\n   - 大面积化学品沾染时立即使用\n   - 拉下喷淋拉杆，站在水流下\n   - 脱去污染衣物（边冲边脱）\n   - 冲洗至少15分钟\n   - 冲洗后就医\n4. 日常维护：\n   - 每周放水测试1次（检查水压和水质）\n   - 每年全面检测1次\n   - 保持周围无障碍物\n   - 冬季防冻保护', '洗眼器,喷淋,化学品溅入,冲洗,应急,安全设施,维护', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"位置要求\",\"content\":\"10秒内到达，通道无障碍\"},{\"stepNumber\":2,\"title\":\"洗眼器使用\",\"content\":\"撑开眼睑冲洗至少15分钟，冲洗后就医\"},{\"stepNumber\":3,\"title\":\"紧急喷淋\",\"content\":\"拉下拉杆，边冲边脱衣物，冲洗15分钟\"},{\"stepNumber\":4,\"title\":\"日常维护\",\"content\":\"每周放水测试，每年全面检测\"}]', 8, 708, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (46, '安全规范', NULL, '易燃易爆化学品的存储和使用规范？', '⚠️ 易燃易爆化学品存储使用规范：\n1. 存储规范：\n   - 存放在专用防爆柜中，柜体接地防静电\n   - 易燃液体总量不超过实验室允许的最大存储量\n   - 远离热源、明火和电气设备\n   - 与氧化剂、强酸等分开存放\n   - 保持良好通风，温度不超过30℃\n2. 使用规范：\n   - 使用前检查容器是否完好，标签是否清晰\n   - 在通风橱内操作，远离明火和热源\n   - 使用防爆冰箱存储需冷藏的易燃液体\n   - 取用后立即盖紧瓶盖\n   - 禁止用明火直接加热易燃液体，使用水浴或油浴\n3. 应急处理：\n   - 小面积着火：用灭火毯覆盖或干粉灭火器\n   - 大面积着火：立即撤离并报警\n   - 泄漏：用吸附棉吸附，保持通风，严禁明火\n4. 常见易燃品：乙醚（闪点-45℃）、丙酮（闪点-20℃）、甲醇、乙醇、甲苯等', '易燃易爆,防爆柜,化学品存储,通风橱,灭火毯,闪点,危险', 1, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"存储规范\",\"content\":\"防爆柜存放，接地防静电，远离热源\"},{\"stepNumber\":2,\"title\":\"使用规范\",\"content\":\"通风橱操作，远离明火，用后盖紧\"},{\"stepNumber\":3,\"title\":\"加热规范\",\"content\":\"禁明火直接加热，使用水浴或油浴\"},{\"stepNumber\":4,\"title\":\"应急-着火\",\"content\":\"小火用灭火毯，大火撤离报警\"},{\"stepNumber\":5,\"title\":\"应急-泄漏\",\"content\":\"吸附棉吸附，保持通风，严禁明火\"}]', 10, 709, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (47, '安全规范', NULL, '可以不戴手套操作化学试剂吗？', '⚠️ 安全警告：严禁不戴手套操作化学试剂！\n\n操作化学试剂必须佩戴防护手套，原因如下：\n1. 皮肤吸收：许多化学试剂可通过皮肤渗透进入体内，如苯、苯胺、有机磷等，即使少量也可能导致中毒\n2. 腐蚀伤害：强酸（硫酸、盐酸、硝酸）和强碱（氢氧化钠）可在数秒内造成皮肤严重灼伤\n3. 过敏反应：部分化学品可引起接触性皮炎或过敏反应\n4. 手套选择：\n   - 一般化学品：丁腈手套（耐大部分有机溶剂）\n   - 强腐蚀性：氯丁橡胶手套或丁基橡胶手套\n   - 剧毒化学品：双层手套（内层丁腈+外层氯丁）\n5. 手套使用注意：\n   - 使用前检查有无破损穿孔\n   - 接触不同化学品需更换手套\n   - 脱手套时由内向外翻卷，避免接触污染面\n   - 一次性手套不可重复使用', '手套,化学试剂,防护,皮肤吸收,腐蚀,丁腈手套,安全,禁止', 1, 'TEXT', NULL, NULL, 8, 710, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (48, '安全规范', NULL, '实验室废液如何正确处理？', '实验室废液正确处理规范：\n1. 分类收集（严禁混合！）：\n   - 含重金属废液（含汞、铬、铅、镉等）：单独收集，贴\"含重金属废液\"标签\n   - 有机废液（含卤代烃、非卤代烃）：分开收集，贴\"有机废液\"标签\n   - 酸性废液：收集至专用酸液桶\n   - 碱性废液：收集至专用碱液桶\n   - 含氰废液：单独收集，调pH>10防止产生HCN气体\n   - 生物废液：高压灭菌后处理\n2. 收集容器要求：\n   - 使用专用废液桶，材质与废液相容\n   - 桶内废液不超过容器容积的3/4\n   - 贴标签注明：废液成分、收集人、收集日期\n3. ⚠️ 严禁事项：\n   - 严禁将不同类别废液混合（可能发生剧烈反应！）\n   - 严禁直接倒入下水道\n   - 严禁在实验室外随意倾倒\n4. 处置流程：收集满后联系有资质的危废处理单位统一回收处置', '废液,废弃物,分类收集,重金属,有机废液,危险废物,环保', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"分类收集\",\"content\":\"重金属、有机、酸、碱、含氰分别收集\"},{\"stepNumber\":2,\"title\":\"容器要求\",\"content\":\"专用废液桶，不超3/4，贴标签\"},{\"stepNumber\":3,\"title\":\"严禁混合\",\"content\":\"不同类别废液严禁混合！\"},{\"stepNumber\":4,\"title\":\"处置流程\",\"content\":\"联系有资质危废处理单位回收\"}]', 10, 711, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (49, '常见问题', NULL, '如何预约实验室设备？', '设备预约操作步骤：\n1. 登录系统：使用学号/工号和密码登录实验室预约管理系统\n2. 选择设备：在设备列表中浏览或搜索需要的设备，点击设备查看详情和可用时间段\n3. 提交预约：\n   - 选择预约日期和时间段（开始时间-结束时间）\n   - 填写实验项目名称和预约事由\n   - 填写参与人数\n   - 确认提交\n4. 等待审核：提交后状态为\"待审核\"，实验室管理员会在1个工作日内审核\n5. 审核结果：\n   - 通过：收到通知，按预约时间使用设备\n   - 拒绝：查看拒绝原因，修改后可重新提交\n6. 使用设备：按预约时间到达实验室，签到使用\n7. 完成确认：使用完毕后在系统中确认完成\n\n注意事项：\n- 需提前24小时预约\n- 单次预约不超过8小时\n- 如需取消，至少提前2小时操作\n- 连续3次爽约将限制预约权限7天', '预约,设备预约,审核,时间段,预约流程,常见问题', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"登录系统\",\"content\":\"使用学号/工号登录\"},{\"stepNumber\":2,\"title\":\"选择设备\",\"content\":\"浏览搜索设备，查看可用时段\"},{\"stepNumber\":3,\"title\":\"提交预约\",\"content\":\"选择日期时段，填写项目信息\"},{\"stepNumber\":4,\"title\":\"等待审核\",\"content\":\"管理员1个工作日内审核\"},{\"stepNumber\":5,\"title\":\"使用设备\",\"content\":\"按预约时间到达签到使用\"},{\"stepNumber\":6,\"title\":\"完成确认\",\"content\":\"使用完毕确认完成\"}]', 15, 800, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (50, '常见问题', NULL, '设备预约时间冲突怎么办？', '预约时间冲突解决方案：\n1. 查看冲突原因：系统提示时间冲突表示该设备在您选择的时间段内已有其他预约\n2. 解决方法：\n   - 更换时间段：查看设备可用时间段，选择其他空闲时段预约\n   - 缩短预约时间：缩短使用时长，避开已预约时段\n   - 更换日期：选择其他日期预约\n   - 更换同类设备：查看是否有同类型设备可用\n3. 查看预约日历：在设备详情页查看预约日历，直观了解设备占用情况\n4. 预约规则：\n   - 同一设备同一时间段只能有一个预约\n   - 时间冲突判断规则：新预约时段与已有预约时段有重叠即冲突\n   - 冲突公式：新开始时间 < 已有结束时间 AND 新结束时间 > 已有开始时间\n5. 建议：提前规划实验时间，错峰预约热门设备', '预约冲突,时间段,设备预约,冲突检测,常见问题', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"查看冲突原因\",\"content\":\"该时段已有其他预约\"},{\"stepNumber\":2,\"title\":\"更换时间段\",\"content\":\"选择其他空闲时段\"},{\"stepNumber\":3,\"title\":\"缩短预约时间\",\"content\":\"避开已预约时段\"},{\"stepNumber\":4,\"title\":\"更换同类设备\",\"content\":\"查看同类型设备可用性\"},{\"stepNumber\":5,\"title\":\"查看预约日历\",\"content\":\"直观了解设备占用情况\"}]', 10, 801, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (51, '常见问题', NULL, '设备报修流程是什么？', '设备报修操作流程：\n1. 发现故障：使用设备时发现异常或故障，立即停止使用\n2. 提交报修：\n   - 在系统中进入设备详情页，点击\"报修\"按钮\n   - 或在维修管理模块中点击\"新建工单\"\n   - 填写故障描述（尽量详细：现象、发生时间、操作步骤等）\n   - 上传故障照片（如有）\n   - 选择优先级：紧急/高/中/低\n3. 工单处理：\n   - 待处理：等待维修人员接单\n   - 处理中：维修人员已接单正在处理\n   - 已完成：维修完成，确认设备恢复正常\n4. 确认验收：设备修复后，预约使用验证是否正常\n5. 评价反馈：对维修服务进行评价\n\n注意：紧急故障（如漏电、冒烟、异响）请立即断电并电话通知实验室管理员！', '报修,维修,故障,工单,报修流程,常见问题', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"发现故障\",\"content\":\"立即停止使用设备\"},{\"stepNumber\":2,\"title\":\"提交报修\",\"content\":\"填写故障描述，上传照片，选优先级\"},{\"stepNumber\":3,\"title\":\"等待处理\",\"content\":\"维修人员接单处理\"},{\"stepNumber\":4,\"title\":\"确认验收\",\"content\":\"设备修复后验证是否正常\"},{\"stepNumber\":5,\"title\":\"评价反馈\",\"content\":\"对维修服务进行评价\"}]', 10, 802, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (52, '常见问题', NULL, '设备校准到期了怎么办？', '设备校准到期处理流程：\n1. 查看校准状态：在设备详情页查看校准日期和下次校准日期\n2. 系统提醒：校准到期前15天，系统会自动发送提醒通知\n3. 校准流程：\n   - 联系设备管理员或校准机构\n   - 安排校准时间（校准期间设备状态变为\"校准中\"）\n   - 校准完成后更新校准记录：校准日期、校准结果、校准证书编号、校准机构\n   - 更新下次校准日期（本次校准日期+校准周期）\n4. 校准结果：\n   - 合格：设备恢复正常可用状态\n   - 不合格：设备需维修或降级使用，贴\"校准不合格\"标识\n5. 注意事项：\n   - 校准过期设备不得用于精密测量和出具检测报告\n   - 常见设备校准周期：分析天平90天，分光光度计180天，pH计30天\n   - 校准记录需存档备查', '校准,校准到期,校准记录,合格,不合格,常见问题', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"查看校准状态\",\"content\":\"设备详情页查看校准日期\"},{\"stepNumber\":2,\"title\":\"系统提醒\",\"content\":\"到期前15天自动通知\"},{\"stepNumber\":3,\"title\":\"安排校准\",\"content\":\"联系校准机构，设备状态变为校准中\"},{\"stepNumber\":4,\"title\":\"更新记录\",\"content\":\"校准日期、结果、证书、下次校准日期\"},{\"stepNumber\":5,\"title\":\"校准结果处理\",\"content\":\"合格恢复使用，不合格维修或降级\"}]', 8, 803, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (53, '常见问题', NULL, '如何查看设备的使用记录和状态？', '查看设备使用记录和状态的方法：\n1. 设备列表页：在设备管理模块查看所有设备列表，可按分类、状态、实验室筛选\n2. 设备详情页：点击设备名称进入详情页，查看：\n   - 基本信息：名称、型号、编号、位置、购置日期\n   - 当前状态：可用/使用中/维修中/校准中/已报废\n   - 校准信息：上次校准日期、下次校准日期、校准周期\n   - 预约记录：该设备的所有预约历史\n   - 维修记录：该设备的所有维修工单\n   - 状态变更日志：设备状态变更历史\n3. 不同角色的查看权限：\n   - 学生：查看自己预约的设备记录\n   - 教师：查看本部门设备记录\n   - 实验室管理员：查看本实验室所有设备记录\n   - 系统管理员：查看所有设备记录\n4. 数据导出：支持导出设备使用统计报表（Excel格式）', '设备状态,使用记录,预约记录,维修记录,查看权限,常见问题', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"设备列表页\",\"content\":\"按分类、状态、实验室筛选\"},{\"stepNumber\":2,\"title\":\"设备详情页\",\"content\":\"基本信息、状态、校准、预约、维修记录\"},{\"stepNumber\":3,\"title\":\"查看权限\",\"content\":\"不同角色查看不同范围数据\"},{\"stepNumber\":4,\"title\":\"数据导出\",\"content\":\"支持导出Excel统计报表\"}]', 8, 804, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (54, '常见问题', NULL, '如何修改个人信息和密码？', '修改个人信息和密码操作：\n1. 修改个人信息：\n   - 登录系统后，点击右上角头像 → 个人中心\n   - 可修改：真实姓名、邮箱、手机号、所属部门、头像\n   - 修改后点击保存\n2. 修改密码：\n   - 个人中心 → 修改密码\n   - 输入当前密码\n   - 输入新密码（要求：8-20位，包含字母和数字）\n   - 确认新密码\n   - 点击确认修改\n3. 忘记密码：\n   - 在登录页面点击\"忘记密码\"\n   - 输入注册邮箱\n   - 系统发送重置链接到邮箱\n   - 通过链接设置新密码\n4. 安全建议：\n   - 密码不要使用生日、学号等简单组合\n   - 定期更换密码（建议每3个月）\n   - 不要与他人共享账号密码', '修改密码,个人信息,忘记密码,安全,常见问题', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"修改个人信息\",\"content\":\"头像→个人中心→修改→保存\"},{\"stepNumber\":2,\"title\":\"修改密码\",\"content\":\"个人中心→修改密码→输入新旧密码\"},{\"stepNumber\":3,\"title\":\"忘记密码\",\"content\":\"登录页→忘记密码→邮箱重置\"},{\"stepNumber\":4,\"title\":\"安全建议\",\"content\":\"定期更换，不共享密码\"}]', 10, 805, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (55, '常见问题', NULL, '系统支持哪些角色？各有什么权限？', '系统角色和权限说明：\n1. 系统管理员（SYSTEM_ADMIN）：\n   - 全部功能权限\n   - 用户管理、角色管理、系统配置\n   - 所有设备、预约、维修数据查看\n2. 实验室管理员（LAB_ADMIN）：\n   - 本实验室设备管理（增删改查）\n   - 预约审核、维修工单分配\n   - 本实验室数据统计和导出\n   - 知识库管理\n3. 教师（TEACHER）：\n   - 预约设备、查看本部门设备\n   - 审核学生预约（如设为审核人）\n   - 提交设备报修\n   - 使用AI助手\n4. 学生（STUDENT）：\n   - 预约设备（仅查看自己的预约）\n   - 提交设备报修\n   - 使用AI助手\n   - 查看设备基本信息\n5. 维护人员（MAINTAINER）：\n   - 接收和处修工单\n   - 更新维修进度和结果\n   - 设备校准管理\n   - 查看设备状态和维护记录', '角色,权限,管理员,教师,学生,维护人员,RBAC,常见问题', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"系统管理员\",\"content\":\"全部权限，用户角色系统管理\"},{\"stepNumber\":2,\"title\":\"实验室管理员\",\"content\":\"本实验室设备预约维修管理\"},{\"stepNumber\":3,\"title\":\"教师\",\"content\":\"预约审核报修AI助手\"},{\"stepNumber\":4,\"title\":\"学生\",\"content\":\"预约报修AI助手\"},{\"stepNumber\":5,\"title\":\"维护人员\",\"content\":\"维修工单校准管理\"}]', 12, 806, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (56, '常见问题', NULL, '如何导出统计数据？', '数据导出操作说明：\n1. 统计导出入口：\n   - 数据统计模块 → 导出按钮\n   - 支持导出：预约统计、设备使用统计、维修统计、用户活跃度\n2. 导出格式：Excel（.xlsx）\n3. 导出步骤：\n   - 选择统计类型（预约/设备/维修/用户）\n   - 选择时间范围（近7天/近30天/近90天/自定义）\n   - 选择导出维度（按设备/按用户/按实验室）\n   - 点击\"导出\"按钮\n   - 等待生成完成，自动下载\n4. 权限说明：\n   - 系统管理员：可导出所有数据\n   - 实验室管理员：可导出本实验室数据\n   - 教师/学生：无导出权限\n5. 数据库备份导出：\n   - 系统管理 → 数据库备份\n   - 支持手动备份和自动定时备份\n   - 备份文件格式：.sql\n   - 可设置备份保留天数（默认30天）', '导出,统计,Excel,数据备份,常见问题', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"选择统计类型\",\"content\":\"预约/设备/维修/用户统计\"},{\"stepNumber\":2,\"title\":\"选择时间范围\",\"content\":\"7天/30天/90天/自定义\"},{\"stepNumber\":3,\"title\":\"选择导出维度\",\"content\":\"按设备/用户/实验室\"},{\"stepNumber\":4,\"title\":\"点击导出\",\"content\":\"等待生成，自动下载Excel\"},{\"stepNumber\":5,\"title\":\"数据库备份\",\"content\":\"系统管理→数据库备份→手动/定时\"}]', 8, 807, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (57, '设备操作手册', 60, '实时荧光定量PCR仪如何操作？', '实时荧光定量PCR仪操作步骤：\n1. 开机预热：打开仪器电源，启动QuantStudio软件，预热15分钟\n2. 准备反应板：在96孔板中按顺序加入PCR反应体系，每孔20-50μL，用光学膜密封\n3. 离心：将反应板放入离心机，1000rpm离心1分钟，排除气泡\n4. 放入仪器：打开仪器盖，将反应板放入样品槽（A1角对准左上角），关闭盖子\n5. 设置程序：\n   - 选择实验类型（相对定量/绝对定量/基因分型）\n   - 设置热循环程序和荧光采集步骤\n   - 选择检测通道（FAM/VIC/ROX/Cy5等）\n   - 设置参比染料（通常ROX）\n6. 运行实验：确认设置无误后点击Run，运行时间约1.5-2小时\n7. 数据分析：运行结束后查看扩增曲线、Ct值、熔解曲线，导出数据报告', 'PCR仪,荧光定量,qPCR,QuantStudio,扩增曲线,Ct值,操作', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"开机预热\",\"content\":\"打开电源，启动软件，预热15分钟\",\"duration\":15},{\"stepNumber\":2,\"title\":\"准备反应板\",\"content\":\"96孔板加反应体系，光学膜密封\",\"duration\":20},{\"stepNumber\":3,\"title\":\"离心排气泡\",\"content\":\"1000rpm离心1分钟\",\"duration\":2},{\"stepNumber\":4,\"title\":\"放入仪器\",\"content\":\"A1角对准左上角放入\",\"duration\":2},{\"stepNumber\":5,\"title\":\"设置程序\",\"content\":\"实验类型、热循环、检测通道\",\"duration\":10},{\"stepNumber\":6,\"title\":\"运行实验\",\"content\":\"确认设置后Run，约1.5-2小时\",\"duration\":120},{\"stepNumber\":7,\"title\":\"数据分析\",\"content\":\"扩增曲线、Ct值、熔解曲线\",\"duration\":15}]', 10, 102, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (58, '设备操作手册', 30, '分析天平如何正确使用？', '分析天平操作步骤：\n1. 预热：开机预热至少30分钟（精密称量需预热1小时以上）\n2. 调水平：观察天平上的水平气泡，调节底脚螺丝使气泡居中\n3. 校准：执行内部校准（按CAL键）或外部校准（用标准砝码），校准完毕显示零点\n4. 去皮：放上称量纸或称量容器，按Tare/Zero键去皮\n5. 称量：\n   - 直接称量法：将样品直接放在称量纸上\n   - 减量法：先称量瓶+样品总重，倒出部分样品后再称量，差值即为样品量\n   - 加量法：去皮后逐步加入样品至目标重量\n6. 读数：待读数稳定标志出现后记录数据，精确至0.1mg\n7. 清理：称量完毕后用软毛刷清理称量盘，关闭天平门\n8. 关机：短时间不用按Standby，长时间不用关机并盖上防尘罩', '分析天平,称量,校准,去皮,减量法,精密称量,操作', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"预热\",\"content\":\"开机预热至少30分钟\",\"duration\":30},{\"stepNumber\":2,\"title\":\"调水平\",\"content\":\"调节底脚螺丝使气泡居中\",\"duration\":2},{\"stepNumber\":3,\"title\":\"校准\",\"content\":\"内校或外校砝码校准\",\"duration\":5},{\"stepNumber\":4,\"title\":\"去皮\",\"content\":\"放称量纸/容器，按Tare键\",\"duration\":3},{\"stepNumber\":5,\"title\":\"称量\",\"content\":\"直接法/减量法/加量法\",\"duration\":10},{\"stepNumber\":6,\"title\":\"读数\",\"content\":\"稳定标志出现后记录\",\"duration\":3},{\"stepNumber\":7,\"title\":\"清理关机\",\"content\":\"软毛刷清理，盖防尘罩\",\"duration\":5}]', 10, 103, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (59, '设备操作手册', 20, '电热恒温干燥箱如何操作？', '电热恒温干燥箱操作步骤：\n1. 放入样品：将需干燥的样品放入干燥箱内，物品间留有间隙，利于热风循环\n2. 关门：确认箱门关闭严密\n3. 设定温度：按SET键进入温度设定，用上下键调整至所需温度（常用105℃烘干玻璃器皿）\n4. 启动加热：确认设定后开始加热，观察温度上升\n5. 设定时间：如需定时，设置干燥时间（通常2-4小时）\n6. 干燥过程：观察温度显示是否稳定在设定值，PID自整定后温度波动应≤±1℃\n7. 取出样品：\n   - 干燥完成后等待自然降温至60℃以下\n   - 戴隔热手套取出物品\n   - 热物品放入干燥器中冷却\n8. 关机：关闭电源开关，长期不用拔掉电源插头\n\n⚠️ 注意：易燃易爆物品禁止放入干燥箱！温度不超过300℃！', '干燥箱,恒温,烘干,温度设定,玻璃器皿,操作', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"放入样品\",\"content\":\"物品间留间隙，利于热风循环\",\"duration\":5},{\"stepNumber\":2,\"title\":\"设定温度\",\"content\":\"常用105℃烘干玻璃器皿\",\"duration\":3},{\"stepNumber\":3,\"title\":\"启动加热\",\"content\":\"观察温度上升至设定值\",\"duration\":20},{\"stepNumber\":4,\"title\":\"设定时间\",\"content\":\"通常2-4小时\",\"duration\":2},{\"stepNumber\":5,\"title\":\"干燥过程\",\"content\":\"观察温度稳定，波动≤±1℃\",\"duration\":120},{\"stepNumber\":6,\"title\":\"取出样品\",\"content\":\"降温至60℃以下，戴隔热手套\",\"duration\":30},{\"stepNumber\":7,\"title\":\"关机\",\"content\":\"关闭电源，长期不用拔插头\",\"duration\":2}]', 8, 104, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (60, '设备操作手册', 40, '紫外可见分光光度计如何操作？', '紫外可见分光光度计操作步骤：\n1. 开机预热：打开仪器电源和电脑，启动操作软件，预热30分钟\n2. 选择测量模式：根据实验需求选择吸光度(Abs)、透射率(T%)或浓度模式\n3. 设置波长：输入测定波长（如核酸260nm，蛋白质280nm，或全波长扫描模式）\n4. 空白调零：\n   - 在两个比色皿中放入空白溶剂\n   - 放入参比池和样品池\n   - 点击\"调零\"或\"基线校正\"\n5. 样品测定：\n   - 将样品池中的空白溶剂替换为待测样品\n   - 点击\"测量\"读取吸光度值\n   - 每个样品测定3次取平均值\n6. 全波长扫描（可选）：设置扫描范围（如190-800nm），执行扫描获取吸收光谱\n7. 数据处理：导出测量数据，绘制标准曲线或吸收光谱图\n8. 关机：先关闭软件，再关闭仪器电源，取出比色皿清洗', '分光光度计,紫外,吸光度,波长,比色皿,调零,操作', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"开机预热\",\"content\":\"打开电源和软件，预热30分钟\",\"duration\":30},{\"stepNumber\":2,\"title\":\"选择模式\",\"content\":\"吸光度/透射率/浓度模式\",\"duration\":2},{\"stepNumber\":3,\"title\":\"设置波长\",\"content\":\"输入测定波长或全波长扫描\",\"duration\":3},{\"stepNumber\":4,\"title\":\"空白调零\",\"content\":\"空白溶剂放入后调零\",\"duration\":5},{\"stepNumber\":5,\"title\":\"样品测定\",\"content\":\"替换样品后测量，3次取平均\",\"duration\":10},{\"stepNumber\":6,\"title\":\"全波长扫描\",\"content\":\"190-800nm范围扫描\",\"duration\":10},{\"stepNumber\":7,\"title\":\"数据处理\",\"content\":\"导出数据，绘制曲线\",\"duration\":10},{\"stepNumber\":8,\"title\":\"关机\",\"content\":\"先关软件再关仪器，清洗比色皿\",\"duration\":5}]', 10, 105, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
INSERT INTO `knowledge_base` VALUES (61, '设备操作手册', 80, '高效液相色谱仪HPLC-1260如何操作？', 'Agilent 1260 HPLC操作步骤：\n1. 准备流动相：配制所需流动相，0.45μm滤膜过滤，超声脱气15分钟\n2. 开机：依次打开脱气机→泵→柱温箱→检测器→自动进样器，启动ChemStation软件\n3. 系统冲洗：用初始流动相冲洗系统10-15分钟，流速1mL/min，排除管路气泡\n4. 平衡色谱柱：以分析流速平衡色谱柱30-60分钟，观察基线平稳\n5. 设置方法：\n   - 设定流速、柱温、检测波长\n   - 设置梯度洗脱程序（如需）\n   - 设置进样体积（通常10-20μL）\n6. 系统适用性：进标准品溶液，检查理论塔板数≥2000，分离度≥1.5，拖尾因子0.8-1.5\n7. 样品分析：依次进样标准品和样品，记录色谱图\n8. 关机：先用高水相冲洗10分钟→再用甲醇/乙腈冲洗20分钟→停泵→关闭各模块', 'HPLC,1260,色谱仪,流动相,梯度洗脱,进样,操作', 0, 'TEXT', NULL, '[{\"stepNumber\":1,\"title\":\"准备流动相\",\"content\":\"配制过滤脱气\",\"duration\":30},{\"stepNumber\":2,\"title\":\"开机\",\"content\":\"脱气机→泵→柱温箱→检测器→进样器\",\"duration\":10},{\"stepNumber\":3,\"title\":\"系统冲洗\",\"content\":\"初始流动相冲洗10-15分钟\",\"duration\":15},{\"stepNumber\":4,\"title\":\"平衡色谱柱\",\"content\":\"分析流速平衡30-60分钟\",\"duration\":45},{\"stepNumber\":5,\"title\":\"设置方法\",\"content\":\"流速、柱温、波长、梯度程序\",\"duration\":10},{\"stepNumber\":6,\"title\":\"系统适用性\",\"content\":\"进标准品检查塔板数和分离度\",\"duration\":15},{\"stepNumber\":7,\"title\":\"样品分析\",\"content\":\"依次进样，记录色谱图\",\"duration\":30},{\"stepNumber\":8,\"title\":\"关机冲洗\",\"content\":\"高水相→有机相冲洗后停泵关机\",\"duration\":30}]', 15, 106, 1, '2026-04-24 01:50:07', '2026-04-24 01:50:07', 0);
