  `keywords` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '关键词',
  `is_danger` int NULL DEFAULT 0 COMMENT '是否为危险操作提醒：0-否，1-是',
  `guide_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'TEXT' COMMENT '引导类型：TEXT-纯文本, IMAGE-图文引导',
  `guide_images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '引导图片URL列表（JSON数组）',
  `guide_steps` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '分步骤引导内容（JSON格式）',
