-- ----------------------------
-- Table structure for knowledge_graph_edge
-- ----------------------------
DROP TABLE IF EXISTS `knowledge_graph_edge`;
CREATE TABLE `knowledge_graph_edge`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '边ID',
  `source_node_id` bigint NOT NULL COMMENT '源节点ID',
  `target_node_id` bigint NOT NULL COMMENT '目标节点ID',
  `edge_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '边类型：BELONGS_TO-属于，RELATED_TO-关联，CONTAINS-包含，DEPENDS_ON-依赖',
  `edge_label` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '边标签（如：操作手册、注意事项）',
  `weight` decimal(5, 2) NULL DEFAULT 1.00 COMMENT '权重（用于图算法）',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '关系描述',
  `sort` int NULL DEFAULT 0 COMMENT '排序号',
  `status` int NULL DEFAULT 1 COMMENT '状态：0-隐藏，1-显示',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` int NULL DEFAULT 0 COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_source`(`source_node_id` ASC) USING BTREE,
  INDEX `idx_target`(`target_node_id` ASC) USING BTREE,
  INDEX `idx_edge_type`(`edge_type` ASC) USING BTREE,
  CONSTRAINT `fk_edge_source` FOREIGN KEY (`source_node_id`) REFERENCES `knowledge_graph_node` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fk_edge_target` FOREIGN KEY (`target_node_id`) REFERENCES `knowledge_graph_node` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 96 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '知识图谱边表' ROW_FORMAT = DYNAMIC;

