-- Records of knowledge_graph_edge
-- ----------------------------

-- ----------------------------
-- Table structure for knowledge_graph_node
-- ----------------------------
DROP TABLE IF EXISTS `knowledge_graph_node`;
CREATE TABLE `knowledge_graph_node`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '节点ID',
  `node_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '节点类型：DEVICE-设备，KNOWLEDGE-知识，CATEGORY-分类',
  `node_id` bigint NULL DEFAULT NULL COMMENT '关联实体ID（device_info.id 或 knowledge_base.id）',
  `node_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '节点名称',
  `node_label` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '节点标签（如：光学显微镜）',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '描述',
  `extra_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '扩展数据（JSON，如设备图片URL）',
  `x_position` decimal(10, 2) NULL DEFAULT NULL COMMENT '布局X坐标',
  `y_position` decimal(10, 2) NULL DEFAULT NULL COMMENT '布局Y坐标',
  `size` int NULL DEFAULT 40 COMMENT '节点大小',
  `color` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '节点颜色',
  `sort` int NULL DEFAULT 0 COMMENT '排序号',
  `status` int NULL DEFAULT 1 COMMENT '状态：0-隐藏，1-显示',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` int NULL DEFAULT 0 COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_node_type`(`node_type` ASC) USING BTREE,
  INDEX `idx_node_id`(`node_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 63 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '知识图谱节点表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of knowledge_graph_node
-- ----------------------------

-- ----------------------------
-- Table structure for laboratory
-- ----------------------------
DROP TABLE IF EXISTS `laboratory`;
CREATE TABLE `laboratory`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '瀹為獙瀹?D',
  `lab_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '瀹為獙瀹ょ紪鐮',
  `lab_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '瀹為獙瀹ゅ悕绉',
  `lab_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '瀹為獙瀹ょ被鍨嬶紙鐗╃悊/鍖栧?/鐢熺墿/璁＄畻鏈?鍏朵粬锛',
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '瀹為獙瀹や綅缃',
  `floor` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '鎵?湪妤煎眰',
  `building` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '鎵?湪寤虹瓚',
  `area` decimal(10, 2) NULL DEFAULT NULL COMMENT '闈㈢Н锛堝钩鏂圭背锛',
  `capacity` int NULL DEFAULT NULL COMMENT '瀹圭撼浜烘暟',
  `responsible_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '璐熻矗浜哄?鍚',
  `responsible_phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '璐熻矗浜虹數璇',
  `responsible_email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '璐熻矗浜洪偖绠',
  `open_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '08:00' COMMENT '寮?斁鏃堕棿寮??',
  `close_time` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '20:00' COMMENT '寮?斁鏃堕棿缁撴潫',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '瀹為獙瀹ょ畝浠',
  `equipment_count` int NULL DEFAULT 0 COMMENT '璁惧?鏁伴噺',
  `status` int NULL DEFAULT 1 COMMENT '鐘舵?锛?-鍋滅敤锛?-姝ｅ父',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_lab_code`(`lab_code` ASC) USING BTREE,
  INDEX `idx_lab_name`(`lab_name` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 16 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '瀹為獙瀹や俊鎭?〃' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of laboratory
-- ----------------------------

