-- ----------------------------
-- Table structure for repair_order
-- ----------------------------
DROP TABLE IF EXISTS `repair_order`;
CREATE TABLE `repair_order`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '工单ID',
  `order_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '工单编号',
  `device_id` bigint NOT NULL COMMENT '设备ID',
  `reporter_id` bigint NOT NULL COMMENT '报修人ID',
  `fault_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '故障描述',
  `image_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '故障图片路径',
  `report_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '报修时间',
  `status` int NULL DEFAULT 0 COMMENT '状态：0-待处理，1-处理中，2-已完成，3-已关闭',
  `handler_id` bigint NULL DEFAULT NULL COMMENT '维修人员ID',
  `priority` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'NORMAL' COMMENT '优先级：URGENT-紧急，HIGH-高，NORMAL-普通，LOW-低',
  `handle_start_time` datetime NULL DEFAULT NULL COMMENT '维修开始时间',
  `handle_end_time` datetime NULL DEFAULT NULL COMMENT '维修完成时间',
  `fault_cause` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '故障原因',
  `repair_solution` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '维修方案',
  `replace_parts` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更换配件',
  `repair_cost` decimal(10, 2) NULL DEFAULT NULL COMMENT '维修费用',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` int NULL DEFAULT 0 COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_order_no`(`order_no` ASC) USING BTREE,
  INDEX `idx_device_id`(`device_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_priority`(`priority` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 35 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '维修工单表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of repair_order
-- ----------------------------

-- ----------------------------
-- Table structure for role_data_scope
-- ----------------------------
DROP TABLE IF EXISTS `role_data_scope`;
CREATE TABLE `role_data_scope`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `role_id` bigint NOT NULL COMMENT '角色ID',
  `scope_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'ALL' COMMENT '范围类型：ALL-全部，DEPT-本部门，SELF-仅本人，CUSTOM-自定义',
  `custom_lab_ids` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '自定义实验室ID列表',
  `device_scope` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'VIEW,EDIT' COMMENT '设备权限：VIEW-查看，EDIT-编辑，DELETE-删除，STATUS-状态管理',
  `booking_scope` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'VIEW' COMMENT '预约权限：VIEW-查看，AUDIT-审核，CANCEL-取消，EXPORT-导出',
  `user_scope` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'VIEW' COMMENT '用户权限：VIEW-查看，EDIT-编辑，ROLE-分配角色，DELETE-删除',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_role_id`(`role_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 101 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '角色数据权限表' ROW_FORMAT = DYNAMIC;

